## 3. Vector Embeddings Generation Script

```typescript name=embeddings-generator.ts url=https://github.com/Rolosolo/Coralfil
import { createClient } from '@supabase/supabase-js';
import fetch from 'node-fetch';

const supabase = createClient(
  process.env.SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_KEY!
);

const OPENAI_API_KEY = process.env.OPENAI_API_KEY!;
const EMBEDDING_MODEL = 'text-embedding-3-small';
const EMBEDDING_DIMENSION = 1536;
const BATCH_SIZE = 100; // OpenAI batch processing

// ============================================================================
// EMBEDDING GENERATION
// ============================================================================

interface EmbeddingResponse {
  object: string;
  index: number;
  embedding: number[];
}

interface OpenAIEmbeddingResponse {
  object: string;
  data: EmbeddingResponse[];
  model: string;
  usage: {
    prompt_tokens: number;
    total_tokens: number;
  };
}

async function generateEmbeddings(texts: string[]): Promise<number[][]> {
  try {
    const response = await fetch('https://api.openai.com/v1/embeddings', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${OPENAI_API_KEY}`,
      },
      body: JSON.stringify({
        model: EMBEDDING_MODEL,
        input: texts,
        encoding_format: 'float',
      }),
    });

    if (!response.ok) {
      throw new Error(`OpenAI API error: ${response.status}`);
    }

    const data = (await response.json()) as OpenAIEmbeddingResponse;
    return data.data.map((item) => item.embedding);
  } catch (error) {
    console.error('Error generating embeddings:', error);
    throw error;
  }
}

// ============================================================================
// PAPER EMBEDDINGS
// ============================================================================

async function generatePaperEmbeddings() {
  console.log('📖 Generating embeddings for papers...');

  // Fetch all papers without embeddings
  const { data: papers, error } = await supabase
    .from('papers')
    .select('id, title, abstract, extracted_text')
    .is('embedding', null)
    .limit(10000);

  if (error || !papers) {
    console.error('Error fetching papers:', error);
    return;
  }

  console.log(`Found ${papers.length} papers without embeddings`);

  // Process in batches
  for (let i = 0; i < papers.length; i += BATCH_SIZE) {
    const batch = papers.slice(i, i + BATCH_SIZE);
    console.log(`Processing batch ${Math.floor(i / BATCH_SIZE) + 1}/${Math.ceil(papers.length / BATCH_SIZE)}`);

    // Prepare texts for embedding
    const texts = batch.map((paper) => {
      const title = paper.title || '';
      const abstract = paper.abstract || '';
      const content = paper.extracted_text?.substring(0, 3000) || '';
      return `${title}\n\n${abstract}\n\n${content}`.trim();
    });

    try {
      const embeddings = await generateEmbeddings(texts);

      // Update database with embeddings
      for (let j = 0; j < batch.length; j++) {
        const { error: updateError } = await supabase
          .from('papers')
          .update({ embedding: embeddings[j] })
          .eq('id', batch[j].id);

        if (updateError) {
          console.error(`Error updating paper ${batch[j].id}:`, updateError);
        }
      }

      console.log(`✓ Updated ${batch.length} papers`);

      // Rate limiting
      await new Promise((resolve) => setTimeout(resolve, 2000));
    } catch (error) {
      console.error('Error processing batch:', error);
    }
  }

  console.log('✓ Paper embeddings complete');
}

// ============================================================================
// THREAT & CONDITION EMBEDDINGS
// ============================================================================

async function generateThreatEmbeddings() {
  console.log('⚠️ Generating embeddings for threats...');

  const { data: threats, error } = await supabase
    .from('coral_threats')
