// ============================================================================
// RPC FUNCTION FOR VECTOR SIMILARITY (Execute in Supabase)
// ============================================================================

/*
CREATE OR REPLACE FUNCTION search_papers_by_embedding(
  query_embedding VECTOR(1536),
  similarity_threshold FLOAT DEFAULT 0.5,
  match_count INT DEFAULT 10
)
RETURNS TABLE (
  id UUID,
  title TEXT,
  doi TEXT,
  similarity FLOAT
) AS $$
BEGIN
  RETURN QUERY
  SELECT
    papers.id,
    papers.title,
    papers.doi,
    (papers.embedding <-> query_embedding) * -1 as similarity
  FROM papers
  WHERE papers.embedding IS NOT NULL
    AND (papers.embedding <-> query_embedding) * -1 > similarity_threshold
  ORDER BY papers.embedding <-> query_embedding
  LIMIT match_count;
END;
$$ LANGUAGE plpgsql;
*/

