## 4. Knowledge Query Express Endpoint

```typescript name=query-endpoint.ts url=https://github.com/Rolosolo/Coralfil
import express, { Request, Response } from 'express';
import { createClient } from '@supabase/supabase-js';
import fetch from 'node-fetch';

const router = express.Router();
const supabase = createClient(
  process.env.SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_KEY!
);

const OPENAI_API_KEY = process.env.OPENAI_API_KEY!;

// ============================================================================
// TYPES
// ============================================================================

interface QueryRequest {
  query: string;
  top_k?: number;
  search_type?: 'vector' | 'keyword' | 'hybrid';
  include_compounds?: boolean;
  include_citations?: boolean;
  user_id?: string;
}

interface SearchResult {
  id: string;
  title: string;
  doi: string | null;
  abstract: string | null;
  relevance_score: number;
  search_type: 'vector' | 'keyword';
  compounds: string[];
  citations: string[];
  url?: string;
}

// ============================================================================
// VECTOR SIMILARITY SEARCH
// ============================================================================

async function vectorSearch(queryText: string, topK: number): Promise<SearchResult[]> {
  try {
    // Generate embedding
    const response = await fetch('https://api.openai.com/v1/embeddings', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${OPENAI_API_KEY}`,
      },
      body: JSON.stringify({
        model: 'text-embedding-3-small',
        input: queryText,
        encoding_format: 'float',
      }),
    });

    if (!response.ok) throw new Error(`OpenAI error: ${response.status}`);

    const data = await response.json() as any;
    const queryEmbedding = data.data[0].embedding;

    // Search papers
    const { data: papers, error } = await supabase.rpc(
      'search_papers_by_embedding',
      {
        query_embedding: queryEmbedding,
        similarity_threshold: 0.5,
        match_count: topK,
      }
    );

    if (error) throw error;

    return (papers || []).map((paper: any) => ({
      ...paper,
      search_type: 'vector' as const,
    }));
  } catch (error) {
    console.error('Vector search error:', error);
    return [];
  }
}

// ============================================================================
// FULL-TEXT KEYWORD SEARCH
// ============================================================================

async function keywordSearch(queryText: string, topK: number): Promise<SearchResult[]> {
  try {
    // Use PostgreSQL full-text search
    const { data: papers, error } = await supabase
      .from('papers')
      .select('id, title, doi, abstract, publication_year')
      .or(`title.ilike.%${queryText}%,abstract.ilike.%${queryText}%,full_text.ilike.%${queryText}%`)
      .limit(topK);

    if (error) throw error;

    return (papers || []).map((paper: any) => ({
      id: paper.id,
      title: paper.title,
      doi: paper.doi,
      abstract: paper.abstract,
      relevance_score: 0.7, // Default score for keyword match
      search_type: 'keyword' as const,
      compounds: [],
      citations: [],
    }));
  } catch (error) {
    console.error('Keyword search error:', error);
    return [];
  }
}

// ============================================================================
// HYBRID SEARCH WITH WEIGHTED SCORING
// ============================================================================

async function hybridSearch(
  queryText: string,
  topK: number
): Promise<SearchResult[]> {
  const vectorResults = await vectorSearch(queryText, topK * 2);
  const keywordResults = await keywordSearch(queryText, topK * 2);

  // Merge and deduplicate
  const resultMap = new Map<string, SearchResult>();

  vectorResults.forEach((result) => {
    resultMap.set(result.id, {
      ...result,
      relevance_score: result.relevance_score * 0.7, // Vector weight
    });
  });

  keywordResults.forEach((result) => {
    if (resultMap.has(result.id)) {
      const existing = resultMap.get(result.id)!;
      existing.relevance_score = Math.max(
        existing.relevance_score,
        result.relevance_score * 0.3
      );
    } else {
      resultMap.set(result.id, {
        ...result,
        relevance_score: result.relevance_score * 0.3,
      });
    }
  });

  return Array.from(resultMap.values())
    .sort((a, b) => b.relevance_score - a.relevance_score)
    .slice(0, topK);
}

// ============================================================================
// ENRICHMENT: EXTRACT COMPOUNDS & CITATIONS
// ============================================================================

async function enrichResults(
  results: SearchResult[],
  include_compounds: boolean,
  include_citations: boolean
): Promise<SearchResult[]> {
  for (const result of results) {
    if (include_compounds) {
      const { data: compounds } = await supabase
        .from('paper_compounds')
        .select('compounds(compound_name)')
        .eq('paper_id', result.id);

      result.compounds = compounds?.map((c: any) => c.compounds.compound_name) || [];
    }

    if (include_citations) {
      // Extract citations from abstract/extracted text
      const citationPattern = /([A-Z][a-z]+(?:\s+et\s+al\.)?)\s+(\d{4})/g;
      const abstract = result.abstract || '';
      const matches = [...abstract.matchAll(citationPattern)];
      result.citations = [...new Set(matches.map((m) => `${m[1]} ${m[2]}`))];
    }
  }

  return results;
}

// ============================================================================
// MAIN QUERY ENDPOINT
// ============================================================================

router.post('/api/knowledge/query', async (req: Request<{}, {}, QueryRequest>, res: Response) => {
  const {
    query,
    top_k = 10,
    search_type = 'hybrid',
    include_compounds = true,
    include_citations = true,
    user_id,
  } = req.body;

  if (!query || query.trim().length === 0) {
    return res.status(400).json({ error: 'Query is required' });
  }

  try {
    console.log(`🔍 Executing ${search_type} search: "${query}"`);

    let results: SearchResult[] = [];

    // Perform search based on type
    switch (search_type) {
      case 'vector':
        results = await vectorSearch(query, top_k);
        break;
      case 'keyword':
        results = await keywordSearch(query, top_k);
        break;
      case 'hybrid':
      default:
        results = await hybridSearch(query, top_k);
    }

    // Enrich results
    results = await enrichResults(results, include_compounds, include_citations);

    // Build response URLs
    results.forEach((r) => {
      if (r.doi) {
        r.url = `https://doi.org/${r.doi}`;
      }
    });

    // Log to analytics
    if (user_id) {
      const topResultId = results[0]?.id || null;
      await supabase.from('search_analytics').insert({
        user_id,
        query_text: query,
        query_type: search_type,
        results_count: results.length,
        top_result_id: topResultId,
        timestamp: new Date().toISOString(),
      });
    }

    res.json({
      success: true,
      query,
      search_type,
      results_count: results.length,
      results,
    });
  } catch (error) {
    console.error('Query endpoint error:', error);
    res.status(500).json({
      error: 'Search failed',
      details: error instanceof Error ? error.message : 'Unknown error',
    });
  }
});

// ============================================================================
// ANALYTICS ENDPOINT
// ============================================================================

router.get('/api/knowledge/analytics', async (req: Request, res: Response) => {
  try {
    const { data: analytics, error } = await supabase
      .from('search_analytics')
      .select('*')
      .order('timestamp', { ascending: false })
      .limit(100);

    if (error) throw error;

    // Aggregate stats
    const stats = {
      total_queries: analytics?.length || 0,
      unique_queries: new Set(analytics?.map((a: any) => a.query_text)).size,
      search_types: analytics
        ? analytics.reduce(
            (acc: any, a: any) => {
              acc[a.query_type] = (acc[a.query_type] || 0) + 1;
              return acc;
            },
            {}
          )
        : {},
      recent_queries: analytics?.slice(0, 20),
    };

    res.json(stats);
  } catch (error) {
    res.status(500).json({ error: 'Analytics fetch failed' });
  }
});

export default router;
