function estimateConcentration(
  compound: string,
  paperReferences: number
): {
  min: number;
  optimal: number;
  max: number;
} {
  // Knowledge base of known compound concentrations from literature
  const concentrationDatabase: Record<
    string,
    { min: number; optimal: number; max: number }
  > = {
    Alginate: { min: 1, optimal: 5, max: 20 },
    Chitosan: { min: 0.5, optimal: 2, max: 10 },
    Calcium: { min: 100, optimal: 400, max: 800 },
    GABA: { min: 0.1, optimal: 1, max: 5 },
    Dopamine: { min: 0.05, optimal: 0.5, max: 2 },
    CCA: { min: 1, optimal: 10, max: 50 },
  };

  const base = concentrationDatabase[compound] || { min: 0.1, optimal: 1, max: 10 };

  // Adjust based on literature support
  const confidence = Math.min(1, paperReferences / 10);
  return {
    min: base.min * confidence,
    optimal: base.optimal * confidence,
    max: base.max * confidence,
  };
}

// ============================================================================
