    Hydrogel: 0.79,
  };

  return efficiencyScores[encapsulation_matrix] || 0.65;
}

// ============================================================================
// MAIN HYPOTHESIS GENERATION FUNCTION
// ============================================================================

async function generateHypothesis(
  ingredients: Ingredient[]
): Promise<GeneratedHypothesis | null> {
  try {
    console.log(`🧪 Generating hypothesis for: ${ingredients.map((i) => i.name).join(', ')}`);

    // 1. Retrieve papers mentioning ingredients
    const { data: papers } = await supabase
      .from('compounds')
      .select('id, compound_name')
      .in('compound_name', ingredients.map((i) => i.name));

    const compoundIds = papers?.map((p: any) => p.id) || [];
    console.log(`Found ${compoundIds.length} matching compounds in database`);

    // 2. Fetch paper references for each compound
    const { data: paperCompounds } = await supabase
      .from('paper_compounds')
      .select('compound_id')
      .in('compound_id', compoundIds);

    const papersPerCompound = new Map<string, number>();
    paperCompounds?.forEach((pc: any) => {
      papersPerCompound.set(
        pc.compound_id,
        (papersPerCompound.get(pc.compound_id) || 0) + 1
      );
    });

    // 3. Generate ingredient hypotheses
    const ingredientHypotheses: IngredientHypothesis[] = [];

    for (const ingredient of ingredients) {
      const compound = papers?.find(
        (p: any) => p.compound_name.toLowerCase() === ingredient.name.toLowerCase()
      );

      if (!compound) continue;

      const paperCount = papersPerCompound.get(compound.id) || 0;
      const concentration = estimateConcentration(ingredient.name, paperCount);

      ingredientHypotheses.push({
        compound_id: compound.id,
        compound_name: ingredient.name,
        concentration_min_ppm: concentration.min,
        concentration_optimal_ppm: concentration.optimal,
        concentration_max_ppm: concentration.max,
        rationale: `Based on ${paperCount} literature references. Properties: ${JSON.stringify(ingredient.properties || {})}`,
        supporting_papers: paperCount,
        confidence_score: Math.min(1, paperCount / 5), // 5+ papers = high confidence
      });
    }

    // 4. Analyze interactions
    const interactions: InteractionData[] = [];

    for (let i = 0; i < ingredientHypotheses.length; i++) {
      for (let j = i + 1; j < ingredientHypotheses.length; j++) {
        const compA = ingredientHypotheses[i];
        const compB = ingredientHypotheses[j];

        // Query for known interactions in literature
        const { data: knownInteractions } = await supabase
          .from('formulation_interactions')
          .select('interaction_type, optimal_ratio')
          .or(
            `and(compound_a_id.eq.${compA.compound_id},compound_b_id.eq.${compB.compound_id}),and(compound_a_id.eq.${compB.compound_id},compound_b_id.eq.${compA.compound_id})`
          );

        if (knownInteractions && knownInteractions.length > 0) {
          interactions.push({
            compound_a: compA.compound_name,
            compound_b: compB.compound_name,
            interaction_type: knownInteractions[0]
              .interaction_type as any,
            optimal_ratio: knownInteractions[0].optimal_ratio || 1,
            supporting_papers: knownInteractions.length,
          });
        } else {
          // Predict based on charge
          const chargeInt = predictChargeInteraction(
            { name: compA.compound_name, charge: ingredients[i].properties?.charge },
            { name: compB.compound_name, charge: ingredients[j].properties?.charge }
          );

          interactions.push({
            compound_a: compA.compound_name,
            compound_b: compB.compound_name,
            interaction_type: chargeInt.synergy_score > 0.7 ? 'Synergy' : 'Neutral',
            optimal_ratio: 1,
            supporting_papers: 0, // Predicted
          });
        }
      }
    }

    // 5. Analyze settlement cue mimicry
    const settlementCues = await getSettlementCues();
    const neurotransmitterProfile =
      await analyzeNeurotransmitterMimicry(
        ingredientHypotheses.map((i) => i.compound_name)
      );

    // 6. Calculate overall confidence
    const totalPapers = ingredientHypotheses.reduce(
      (sum, i) => sum + i.supporting_papers,
      0
    );
    const avgConfidence =
      ingredientHypotheses.reduce((sum, i) => sum + i.confidence_score, 0) /
      ingredientHypotheses.length;

    // 7. Generate recommendations
    const recommendations: string[] = [];

    if (avgConfidence > 0.7) {
      recommendations.push(
        '✓ HIGH CONFIDENCE: Well-supported by literature'
      );
    } else if (avgConfidence > 0.4) {
      recommendations.push('⚠ MODERATE CONFIDENCE: Some literature support');
    } else {
      recommendations.push('⚠ LOW CONFIDENCE: Limited literature support - recommend pilot testing');
    }

    // Check for synergistic interactions
    const synergies = interactions.filter((i) => i.interaction_type === 'Synergy');
    if (synergies.length > 0) {
      recommendations.push(`✓ SYNERGISTIC POTENTIAL: ${synergies.length} favorable interactions detected`);
    }

    const antagonisms = interactions.filter(
      (i) => i.interaction_type === 'Antagonism'
    );
    if (antagonisms.length > 0) {
      recommendations.push(`⚠ POTENTIAL ANTAGONISMS: ${antagonisms.length} negative interactions - adjust ratios`);
    }

    if (neurotransmitterProfile.neurotransmitters.length > 0) {
      recommendations.push(
        `🧠 NEUROLOGICAL CUES: Mimics ${neurotransmitterProfile.neurotransmitters.join(', ')}`
      );
    }

    return {
      hypothesis_name: `${ingredients.map((i) => i.name).join('-')}-formulation-${new Date().getTime()}`,
      target_application: 'Larval Settlement & Coral Restoration',
      ingredients: ingredientHypotheses,
      interactions,
      settlement_cue_mimicry: neurotransmitterProfile,
      confidence_score: avgConfidence,
      citation_count: totalPapers,
      recommendations,
    };
  } catch (error) {
    console.error('Error generating hypothesis:', error);
    return null;
  }
}

export { generateHypothesis, GeneratedHypothesis };
