## 6. Threat Mitigation Matrix Function

```typescript name=threat-mitigation.ts url=https://github.com/Rolosolo/Coralfil
import { createClient } from '@supabase/supabase-js';

const supabase = createClient(
  process.env.SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_KEY!
);

// ============================================================================
// TYPES
// ============================================================================

interface TreatmentOption {
  treatment_name: string;
  treatment_type: string;
  efficacy_percent: number;
  application_method: string;
  cost_per_unit: number;
  cost_currency: string;
  sample_size: number;
  study_duration_days: number;
  confidence_score: number;
  citations: string[];
  supporting_papers: number;
}

interface ThreatMitigationMatrix {
  threat_name: string;
  iucn_category?: string;
  description?: string;
  affected_genera: string[];
  treatment_options: TreatmentOption[];
  ranked_recommendations: Array<{
    rank: number;
    treatment_name: string;
    efficacy_score: number; // Weighted: efficacy * confidence / cost
    efficacy_percent: number;
    cost_per_unit: number;
    feasibility_score: number; // 0-1 based on ease of application
    roi_score: number; // Return on investment
    supporting_evidence: number;
    recommendation_text: string;
  }>;
  summary_stats: {
    total_treatments: number;
    avg_efficacy: number;
    avg_cost: number;
    most_supported_treatment: string;
  };
}

// ============================================================================
// THREAT RETRIEVAL
// ============================================================================

async function getThreatData(threatName: string) {
  const { data: threat, error: threatError } = await supabase
    .from('coral_threats')
    .select('id, threat_name, iucn_category, description, affected_genera')
    .ilike('threat_name', `%${threatName}%`)
    .single();

  if (threatError || !threat) {
    console.error(`Threat not found: ${threatName}`, threatError);
    return null;
  }

  return threat;
}

// ============================================================================
// TREATMENT RETRIEVAL & ENRICHMENT
// ============================================================================

async function getTreatmentOptions(threat: any): Promise<TreatmentOption[]> {
  // Get all pathogens associated with this threat
  const { data: pathogens } = await supabase
    .from('pathogens')
    .select('id, pathogen_name')
    .eq('threat_id', threat.id);

  if (!pathogens) return [];

  const pathogenIds = pathogens.map((p: any) => p.id);

  // Get all treatments for these pathogens
  const { data: treatments, error: treatmentError } = await supabase
    .from('treatment_efficacy')
    .select(
      `
        id,
        treatment_name,
        treatment_type,
        efficacy_percent,
        application_method,
        cost_per_unit,
        cost_currency,
        sample_size,
        study_duration_days,
        confidence_score,
        paper_id,
        papers(title, authors, doi)
      `
    )
    .in('pathogen_id', pathogenIds);

  if (treatmentError || !treatments) {
    console.error('Error fetching treatments:', treatmentError);
    return [];
  }

  // Group by treatment and aggregate
  const treatmentMap = new Map<string, TreatmentOption>();

  treatments.forEach((t: any) => {
    const key = t.treatment_name;

    if (!treatmentMap.has(key)) {
      treatmentMap.set(key, {
        treatment_name: t.treatment_name,
        treatment_type: t.treatment_type,
        efficacy_percent: t.efficacy_percent,
        application_method: t.application_method,
        cost_per_unit: t.cost_per_unit || 0,
        cost_currency: t.cost_currency,
        sample_size: t.sample_size,
        study_duration_days: t.study_duration_days,
        confidence_score: t.confidence_score,
        citations: [],
        supporting_papers: 0,
      });
    }

    const existing = treatmentMap.get(key)!;
    if (t.papers) {
      const citation = `${t.papers.authors?.[0] || 'Unknown'} et al. (${t.papers.doi || 'unpublished'})`;
      existing.citations.push(citation);
      existing.supporting_papers++;
    }
  });

  return Array.from(treatmentMap.values());
}

// ============================================================================
// FEASIBILITY SCORING
// ============================================================================

function calculateFeasibilityScore(treatment: TreatmentOption): number {
  // Factors: application method, sample size (larger = harder to scale), duration
  let score = 0.5; // Base score

  // Application method feasibility
  const methodScores: Record<string, number> = {
    'Injection': 0.8,
    'Topical': 0.9,
    'Water-based': 0.7,
    'Feeding': 0.75,
    'Thermal': 0.6,
    'Tank-based': 0.5,
  };

  const method = Object.keys(methodScores).find((m) =>
    treatment.application_method?.toLowerCase().includes(m.toLowerCase())
  );

  if (method) score = methodScores[method];

  // Duration factor (shorter studies = less proven scalability)
  if (treatment.study_duration_days && treatment.study_duration_days > 180) {
    score *= 0.95; // Slight boost for long-term studies
  } else if (treatment.study_duration_days && treatment.study_duration_days < 30) {
    score *= 0.8; // Penalty for short-term studies
  }

  // Sample size normalization
  if (treatment.sample_size > 100) {
    score *= 0.9; // Slight penalty for very large sample sizes (harder to scale)
  } else if (treatment.sample_size < 10) {
    score *= 0.7; // Penalty for very small sample sizes (less rigorous)
  }

  return Math.min(1, Math.max(0, score));
}

// ============================================================================
// ROI CALCULATION
// ============================================================================

interface CostBenefitAnalysis {
  cost_per_1000_corals: number;
  expected_survival_gain: number; // percentage points
  survival_value_per_coral: number; // notional value
  roi_percentage: number;
}

function calculateROI(
  treatment: TreatmentOption,
  baseline_survival: number = 60
): CostBenefitAnalysis {
  const coralsPerUnit = 10; // Assumption: 1 unit treats 10 corals
  const costPer1000 = (treatment.cost_per_unit / coralsPerUnit) * 1000;
  const survivalGain = Math.max(0, treatment.efficacy_percent - baseline_survival);

  // Notional value: $10 per coral survived (conservation value)
  const survivalValuePerCoral = 10;
  const totalBenefit = survivalGain * survivalValuePerCoral * 100; // per 100 corals

  const roi_percentage = (totalBenefit - costPer1000) / costPer1000 * 100;

  return {
    cost_per_1000_corals: costPer1000,
    expected_survival_gain: survivalGain,
    survival_value_per_coral: survivalValuePerCoral,
    roi_percentage,
  };
}

// ============================================================================
// COMPOSITE SCORING & RANKING
// ============================================================================

interface RankedRecommendation {
  rank: number;
  treatment_name: string;
  efficacy_score: number;
  efficacy_percent: number;
  cost_per_unit: number;
  feasibility_score: number;
  roi_score: number;
  supporting_evidence: number;
  recommendation_text: string;
}

function rankTreatments(
  treatments: TreatmentOption[]
): RankedRecommendation[] {
  const scored = treatments.map((t) => {
    const feasibility = calculateFeasibilityScore(t);
    const roi = calculateROI(t);

    // Composite score: 40% efficacy, 30% feasibility, 20% cost, 10% evidence
    const efficacyScore =
      (t.efficacy_percent / 100) * 0.4 +
      feasibility * 0.3 +
      Math.max(0, 1 - roi.cost_per_1000_corals / 10000) * 0.2 +
      Math.min(1, t.supporting_papers / 5) * 0.1;

    return {
      treatment_name: t.treatment_name,
      efficacy_score: efficacyScore,
      efficacy_percent: t.efficacy_percent,
      cost_per_unit: t.cost_per_unit,
      feasibility_score: feasibility,
      roi_score: roi.roi_percentage,
      supporting_evidence: t.supporting_papers,
      treatment_type: t.treatment_type,
      confidence_score: t.confidence_score,
      citations: t.citations,
    };
  });

  // Sort by composite score
  scored.sort((a, b) => b.efficacy_score - a.efficacy_score);

  // Generate recommendations
  return scored.map((s, index) => {
    let recommendation_text = '';

    if (s.efficacy_score > 0.8) {
      recommendation_text = '🏆 TOP CHOICE: Excellent efficacy and feasibility';
    } else if (s.efficacy_score > 0.6) {
      recommendation_text = '✓ STRONG OPTION: Good balance of efficacy and feasibility';
    } else if (s.efficacy_score > 0.4) {
      recommendation_text = '⚠ MODERATE: Consider if other options are unavailable';
    } else {
      recommendation_text = '⚠ LOW PRIORITY: Limited efficacy or evidence';
    }

    if (s.efficacy_percent > 80) {
      recommendation_text += ' | Very High Efficacy';
    }

    if (s.roi_score > 100) {
      recommendation_text += ' | Strong ROI';
    }

    if (s.supporting_evidence > 5) {
      recommendation_text += ' | Well-supported by literature';
    }

    return {
      rank: index + 1,
      treatment_name: s.treatment_name,
      efficacy_score: parseFloat(s.efficacy_score.toFixed(3)),
      efficacy_percent: s.efficacy_percent,
      cost_per_unit: s.cost_per_unit,
      feasibility_score: parseFloat(s.feasibility_score.toFixed(3)),
      roi_score: parseFloat(s.roi_score.toFixed(1)),
      supporting_evidence: s.supporting_evidence,
      recommendation_text,
    };
  });
}

// ============================================================================
// MAIN FUNCTION
// ============================================================================

async function threatMitigationMatrix(
  threatName: string
): Promise<ThreatMitigationMatrix | null> {
  try {
    console.log(`🎯 Building threat mitigation matrix for: ${threatName}`);

    // Get threat data
    const threat = await getThreatData(threatName);
    if (!threat) {
      console.error(`Threat "${threatName}" not found in database`);
      return null;
    }

    console.log(`Found threat: ${threat.threat_name} (${threat.iucn_category})`);

    // Get treatment options
    const treatments = await getTreatmentOptions(threat);
    console.log(`Found ${treatments.length} treatment options`);

    if (treatments.length === 0) {
      console.warn('No treatments found for this threat');
    }

    // Rank treatments
    const rankedRecommendations = rankTreatments(treatments);

    // Calculate summary stats
    const summary_stats = {
      total_treatments: treatments.length,
      avg_efficacy:
        treatments.length > 0
          ? treatments.reduce((sum, t) => sum + t.efficacy_percent, 0) /
            treatments.length
          : 0,
      avg_cost:
        treatments.length > 0
          ? treatments.reduce((sum, t) => sum + t.cost_per_unit, 0) /
            treatments.length
          : 0,
      most_supported_treatment:
        treatments.length > 0
          ? treatments.reduce((prev, current) =>
              prev.supporting_papers > current.supporting_papers ? prev : current
            ).treatment_name
          : 'N/A',
    };

    return {
      threat_name: threat.threat_name,
      iucn_category: threat.iucn_category,
      description: threat.description,
      affected_genera: threat.affected_genera,
      treatment_options: treatments,
      ranked_recommendations: rankedRecommendations.slice(0, 5), // Top 5
      summary_stats,
    };
  } catch (error) {
    console.error('Error building threat mitigation matrix:', error);
    return null;
  }
}

