// ============================================================================

function extractDOI(text: string): string | null {
  const doiPattern = /\b(10\.\d{4,}\/\S+)\b/gi;
  const matches = text.match(doiPattern);
  return matches ? matches[0].toLowerCase() : null;
}

function extractCitations(text: string): string[] {
  const citationPattern = /([A-Z][a-z]+(?:\s+(?:and|&)\s+[A-Z][a-z]+)?(?:\s+et\s+al\.)?)\s+(\d{4})/g;
  const citations: string[] = [];
  let match;

  while ((match = citationPattern.exec(text)) !== null) {
    citations.push(`${match[1]} ${match[2]}`);
  }

  return [...new Set(citations)];
}

function extractAuthorsFromHeader(text: string): string[] {
  const headerText = text.substring(0, 2000);

  // Common pattern: "Author1, Author2, and Author3"
  const authorPattern = /^([A-Z][a-z]+\s+[A-Z][a-z\.]*(?:,\s*)?)+/gm;
  const match = headerText.match(authorPattern);

  if (!match) return [];

  return match[0]
    .split(/,\s+and\s+|,\s+|\s+and\s+/)
    .filter((a) => a && a.trim().length > 2);
}

// ============================================================================
// CROSSREF API METADATA ENRICHMENT
// ============================================================================

async function fetchCrossRefMetadata(doi: string): Promise<Partial<ExtractedPaperData>> {
  try {
    const url = `https://api.crossref.org/works/${encodeURIComponent(doi)}`;
    const response = await fetch(url, {
      headers: { 'mailto': CROSSREF_EMAIL }
    });

    if (!response.ok) {
      console.warn(`CrossRef API error for DOI ${doi}: ${response.status}`);
      return {};
    }

    const data = (await response.json()) as CrossRefResponse;
    const msg = data.message;

    return {
      doi,
      title: msg.title?.[0] || null,
      authors: msg.author
        ? msg.author.map((a) => `${a.given} ${a.family}`)
        : [],
      publication_year: msg.published?.['date-parts']?.[0]?.[0] || null,
      journal: msg['container-title']?.[0] || null,
      abstract: msg.abstract || null,
    };
  } catch (error) {
    console.error(`Error fetching CrossRef metadata for ${doi}:`, error);
    return {};
  }
}

// ============================================================================
// ENTITY EXTRACTION (NER FOR CORAL RESEARCH)
// ============================================================================

function extractEntities(text: string): ExtractedEntity[] {
  const entities: ExtractedEntity[] = [];
  const words = text.split(/[\s\n]+/);

  for (let i = 0; i < words.length; i++) {
    const word = words[i].replace(/[.,;:!?()\[\]{}]/g, '');
    const lowerWord = word.toLowerCase();
    const context = words.slice(Math.max(0, i - 5), Math.min(words.length, i + 6)).join(' ');

    // Check coral species
    if (ENTITY_CORPUS.coral_species.some((s) => lowerWord.includes(s.toLowerCase()))) {
      entities.push({
        type: 'species',
        name: word,
        context,
        confidence: 0.9,
      });
    }

    // Check pathogens
    if (ENTITY_CORPUS.pathogens.some((p) => lowerWord.includes(p.toLowerCase()))) {
      entities.push({
        type: 'pathogen',
        name: word,
        context,
        confidence: 0.85,
      });
    }

    // Check compounds
    if (ENTITY_CORPUS.compounds_and_materials.some((c) => lowerWord.includes(c.toLowerCase()))) {
      entities.push({
        type: 'compound',
        name: word,
        context,
        confidence: 0.8,
      });
    }

    // Check techniques
    if (ENTITY_CORPUS.techniques.some((t) => lowerWord.includes(t.toLowerCase()))) {
      entities.push({
        type: 'technique',
        name: word,
        context,
        confidence: 0.75,
      });
    }

    // Check processes
    if (ENTITY_CORPUS.coral_processes.some((p) => lowerWord.includes(p.toLowerCase()))) {
      entities.push({
        type: 'organism',
        name: word,
        context,
        confidence: 0.7,
      });
    }
  }

  // Deduplicate
  const uniqueEntities = new Map<string, ExtractedEntity>();
  entities.forEach((e) => {
    const key = `${e.type}:${e.name.toLowerCase()}`;
    if (!uniqueEntities.has(key)) {
      uniqueEntities.set(key, e);
    }
  });

  return Array.from(uniqueEntities.values());
}

// ============================================================================
// SECTION EXTRACTION & CHUNKING
// ============================================================================

function extractSections(text: string): PaperSection[] {
  const sections: PaperSection[] = [];
  const sectionNames = [
    'Abstract', 'Introduction', 'Methods', 'Materials and Methods',
    'Results', 'Discussion', 'Conclusion', 'Conclusions',
    'References', 'Acknowledgments'
  ];

  let currentSection = 'Preamble';
  let currentContent = '';

  const lines = text.split('\n');

  for (const line of lines) {
    const sectionMatch = sectionNames.find(
      (s) => line.toUpperCase().includes(s.toUpperCase()) && line.length < 60
    );

    if (sectionMatch && currentContent.trim().length > 50) {
      sections.push({
        name: currentSection,
        content: currentContent.trim(),
      });
      currentSection = sectionMatch;
      currentContent = '';
    } else {
      currentContent += line + '\n';
    }
  }

  if (currentContent.trim()) {
    sections.push({
      name: currentSection,
      content: currentContent.trim(),
    });
  }

  return sections;
}

// ============================================================================
// RELEVANCE SCORING FOR CORAL RESEARCH
// ============================================================================

function scoreRelevanceForCoralResearch(text: string): number {
  const coralKeywords = [
    'coral', 'reef', 'bleaching', 'settlement', 'larvae', 'larval',
    'restoration', 'aquaculture', 'reproduction', 'spawning',
    'symbiosis', 'zooxanthellae', 'thermal', 'acidification',
    'conservation', 'chitosan', 'alginate', 'probiotic'
  ];

  const textLower = text.toLowerCase();
  const matchCount = coralKeywords.filter((kw) => textLower.includes(kw)).length;

  // Score based on keyword density
  return Math.min(1, matchCount / coralKeywords.length);
}

// ============================================================================
// DUPLICATE DETECTION
// ============================================================================

async function checkDuplicatePaper(metadata: Partial<ExtractedPaperData>): Promise<boolean> {
  // Check by DOI
  if (metadata.doi) {
    const { data } = await supabase
      .from('papers')
      .select('id')
      .eq('doi', metadata.doi)
      .limit(1);
    if (data && data.length > 0) return true;
  }

  // Check by title (fuzzy match on first 50 chars)
  if (metadata.title) {
    const titleSnippet = metadata.title.substring(0, 50);
    const { data } = await supabase
      .from('papers')
      .select('id')
      .ilike('title', `%${titleSnippet}%`)
      .limit(1);
    if (data && data.length > 0) return true;
  }

  return false;
}

// ============================================================================
// DATABASE INSERTION
// ============================================================================

async function insertPaperAndRelatedData(
  metadata: ExtractedPaperData,
  filePath: string
): Promise<string | null> {
  try {
    // Insert paper record
    const { data: paperData, error: paperError } = await supabase
      .from('papers')
      .insert({
        doi: metadata.doi,
        title: metadata.title,
        authors: metadata.authors,
        publication_year: metadata.publication_year,
        journal: metadata.journal,
        abstract: metadata.abstract,
        full_text: metadata.full_text,
        extracted_text: metadata.full_text.substring(0, 50000),
      })
      .select('id')
      .single();

    if (paperError || !paperData) {
      console.error('Error inserting paper:', paperError);
      return null;
    }

    const paperId = paperData.id;
    console.log(`✓ Paper inserted: ${paperId} - ${metadata.title?.substring(0, 50)}`);

    // Insert compounds
    const compounds = metadata.entities.filter((e) => e.type === 'compound');
    for (const compound of compounds) {
      const { data: existingCompound } = await supabase
        .from('compounds')
        .select('id')
        .eq('compound_name', compound.name)
        .single();

      let compoundId = existingCompound?.id;

      if (!compoundId) {
        const { data: newCompound } = await supabase
          .from('compounds')
          .insert({
            compound_name: compound.name,
            compound_class: 'Unknown',
          })
          .select('id')
          .single();
        compoundId = newCompound?.id;
      }

      if (compoundId) {
        await supabase.from('paper_compounds').insert({
          paper_id: paperId,
          compound_id: compoundId,
          mention_context: compound.context,
          key_finding: compound.context,
        });
      }
    }

    // Insert pathogen references
    const pathogens = metadata.entities.filter((e) => e.type === 'pathogen');
    for (const pathogen of [...new Set(pathogens.map((p) => p.name))]) {
      const { data: existingPathogen } = await supabase
        .from('pathogens')
        .select('id')
        .eq('pathogen_name', pathogen)
        .single();

      if (!existingPathogen) {
        await supabase.from('pathogens').insert({
          pathogen_name: pathogen,
          pathogen_type: 'Unknown',
          host_species: [],
        });
      }
    }

    // Insert coral species references
    const species = metadata.entities.filter((e) => e.type === 'species');
    for (const sp of [...new Set(species.map((s) => s.name))]) {
      // Could create a coral_species table or just track via entities
    }

    return paperId;
  } catch (error) {
    console.error('Error inserting paper and relations:', error);
    return null;
  }
}

// ============================================================================
// WIKI MARKDOWN GENERATION
// ============================================================================

function generateWikiMarkdown(metadata: ExtractedPaperData, paperId: string): string {
  let markdown = `# ${metadata.title || 'Untitled Paper'}\n\n`;
  markdown += `**DOI**: ${metadata.doi ? `[${metadata.doi}](https://doi.org/${metadata.doi})` : 'Not available'}\n\n`;
  markdown += `**Authors**: ${metadata.authors.join(', ') || 'Unknown'}\n\n`;
  markdown += `**Year**: ${metadata.publication_year || 'Unknown'}\n\n`;
  markdown += `**Journal**: ${metadata.journal || 'Unknown'}\n\n`;
  markdown += `**Database ID**: \`${paperId}\`\n\n`;

  if (metadata.abstract) {
    markdown += `## Abstract\n\n${metadata.abstract}\n\n`;
  }

  markdown += `## Key Entities Identified\n\n`;
  markdown += `### Coral Species\n${metadata.entities
    .filter((e) => e.type === 'species')
    .map((e) => `- ${e.name}`)
    .join('\n')}\n\n`;

  markdown += `### Compounds & Materials\n${metadata.entities
    .filter((e) => e.type === 'compound')
    .map((e) => `- ${e.name}`)
    .join('\n')}\n\n`;

  markdown += `### Pathogens & Threats\n${metadata.entities
    .filter((e) => e.type === 'pathogen')
    .map((e) => `- ${e.name}`)
    .join('\n')}\n\n`;

  markdown += `### Techniques\n${metadata.entities
    .filter((e) => e.type === 'technique')
    .map((e) => `- ${e.name}`)
    .join('\n')}\n\n`;

  markdown += `## Paper Sections\n\n`;
  for (const section of metadata.sections) {
    markdown += `### ${section.name}\n\n${section.content.substring(0, 500)}...\n\n`;
  }

  markdown += `---\n*Ingested: ${new Date().toISOString()}*\n`;
  markdown += `*Relevance Score: ${(metadata.relevance_score * 100).toFixed(1)}%*\n`;

  return markdown;
}

// ============================================================================
// MAIN INGESTION PIPELINE
// ============================================================================

async function main() {
  console.log('🚀 Starting PDF Knowledge Ingestion Pipeline\n');
  console.log(`📂 Source Directory: ${KNOWLEDGE_BASE_DIR}`);
  console.log(`📝 Wiki Output: ${WIKI_OUTPUT_DIR}\n`);

  // Ensure wiki output directory exists
  if (!fs.existsSync(WIKI_OUTPUT_DIR)) {
    fs.mkdirSync(WIKI_OUTPUT_DIR, { recursive: true });
  }

  // Find all PDFs
  console.log('🔍 Scanning for PDFs...');
  const pdfPaths = findAllPDFs(KNOWLEDGE_BASE_DIR);
  console.log(`Found ${pdfPaths.length} PDF files\n`);

  if (pdfPaths.length === 0) {
    console.warn('⚠️  No PDFs found. Exiting.');
    return;
  }

  // Process each PDF
  let successCount = 0;
  let skipCount = 0;
  let errorCount = 0;

  for (let i = 0; i < pdfPaths.length; i++) {
    const pdfPath = pdfPaths[i];
    const filename = path.basename(pdfPath);

    console.log(`\n[${i + 1}/${pdfPaths.length}] Processing: ${filename}`);

    try {
      // Extract text
      const text = await extractTextFromPDF(pdfPath);
      if (!text || text.trim().length < 100) {
        console.warn('  ⚠️  No readable text extracted');
        errorCount++;
        continue;
      }

      // Extract metadata
      const doi = extractDOI(text);
      const metadata: ExtractedPaperData = {
        doi,
        title: null,
        authors: extractAuthorsFromHeader(text),
        publication_year: null,
        journal: null,
        abstract: null,
        full_text: text,
        citations: extractCitations(text),
        entities: extractEntities(text),
        sections: extractSections(text),
        relevance_score: scoreRelevanceForCoralResearch(text),
      };

      // Enrich from CrossRef if DOI available
      if (doi) {
        const crossRefData = await fetchCrossRefMetadata(doi);
        Object.assign(metadata, crossRefData);
        console.log(`  ✓ CrossRef metadata enriched`);
        await new Promise((resolve) => setTimeout(resolve, 1000)); // Rate limiting
      }

      // Check for duplicates
      if (await checkDuplicatePaper(metadata)) {
        console.log('  ⊘ Skipped: Duplicate paper');
        skipCount++;
        continue;
      }

      // Insert into database
      const paperId = await insertPaperAndRelatedData(metadata, pdfPath);
      if (!paperId) {
        errorCount++;
        continue;
      }

      // Generate wiki markdown
      const wikiMarkdown = generateWikiMarkdown(metadata, paperId);
      const wikiFilename = `${paperId}-${filename.replace('.pdf', '')}.md`.substring(0, 100);
      const wikiPath = path.join(WIKI_OUTPUT_DIR, wikiFilename);

      fs.writeFileSync(wikiPath, wikiMarkdown, 'utf-8');
      console.log(`  ✓ Wiki markdown created: ${wikiFilename}`);
      console.log(`  📊 Relevance: ${(metadata.relevance_score * 100).toFixed(1)}%`);
      console.log(`  🏷️  Entities: ${metadata.entities.length} (Species: ${metadata.entities.filter((e) => e.type === 'species').length}, Compounds: ${metadata.entities.filter((e) => e.type === 'compound').length})`);

      successCount++;
    } catch (error) {
      console.error(`  ✗ Error:`, error instanceof Error ? error.message : error);
      errorCount++;
    }

    // Respectful rate limiting
    await new Promise((resolve) => setTimeout(resolve, 500));
  }

  // Summary
  console.log(`\n\n${'='.repeat(60)}`);
  console.log(`📊 INGESTION SUMMARY`);
  console.log(`${'='.repeat(60)}`);
  console.log(`✓ Successfully ingested: ${successCount}`);
  console.log(`⊘ Skipped (duplicates): ${skipCount}`);
  console.log(`✗ Errors: ${errorCount}`);
  console.log(`📁 Total files scanned: ${pdfPaths.length}`);
  console.log(`📝 Wiki files created: ${successCount}`);
  console.log(`${'='.repeat(60)}\n`);
}

main().catch((error) => {
  console.error('Fatal error:', error);
  process.exit(1);
});
```

