## 4. Wiki Index Generator

```typescript name=generate-wiki-index.ts
import * as fs from 'fs';
import * as path from 'path';
import { createClient } from '@supabase/supabase-js';

const supabase = createClient(
  process.env.SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_KEY!
);

async function generateWikiIndex() {
  console.log('📚 Generating Wiki Index\n');

  // Fetch all ingested papers
  const { data: papers, error } = await supabase
    .from('papers')
    .select('id, title, authors, publication_year, journal, doi')
    .order('publication_year', { ascending: false })
    .limit(1000);

  if (error || !papers) {
    console.error('Error fetching papers:', error);
    return;
  }

  // Group by year
  const papersByYear = new Map<number, typeof papers>();
  papers.forEach((paper) => {
    const year = paper.publication_year || 0;
    if (!papersByYear.has(year)) {
      papersByYear.set(year, []);
    }
    papersByYear.get(year)!.push(paper);
  });

  // Generate markdown index
  let indexMarkdown = `# Ingested Research Papers Index\n\n`;
  indexMarkdown += `**Total Papers**: ${papers.length}\n\n`;
  indexMarkdown += `*Last Updated*: ${new Date().toISOString()}\n\n`;

  indexMarkdown += `## 📑 Papers by Year\n\n`;

  Array.from(papersByYear.entries())
    .sort((a, b) => b[0] - a[0])
    .forEach(([year, yearPapers]) => {
      indexMarkdown += `### ${year}\n\n`;

      yearPapers.forEach((paper) => {
        const authors = paper.authors?.[0] ? `${paper.authors[0]} et al.` : 'Unknown';
        const doi = paper.doi ? `[DOI](https://doi.org/${paper.doi})` : '';
        const link = `[ingested-papers/${paper.id}](./ingested-papers/${paper.id}.md)`;

        indexMarkdown += `- **${paper.title}** ${link}\n`;
        indexMarkdown += `  - ${authors} (${paper.journal || 'Unknown'})\n`;
        if (doi) indexMarkdown += `  - ${doi}\n`;
        indexMarkdown += `\n`;
      });
    });

  // Write to file
  const indexPath = './docs/science-wiki/ingested-papers-index.md';
  fs.writeFileSync(indexPath, indexMarkdown, 'utf-8');

  console.log(`✓ Wiki index generated: ${indexPath}`);
  console.log(`✓ Total papers indexed: ${papers.length}`);
}

generateWikiIndex().catch(console.error);
```

## 5. Validation & Quality Checks Script

```typescript name=validate-ingested-papers.ts
import { createClient } from '@supabase/supabase-js';

const supabase = createClient(
  process.env.SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_KEY!
);

async function validateIngestedPapers() {
  console.log('🔍 Validating Ingested Papers\n');

  const { data: papers, error } = await supabase
    .from('papers')
    .select('id, title, doi, abstract, full_text, publication_year')
    .limit(1000);

  if (error || !papers) {
    console.error('Error fetching papers:', error);
    return;
  }

  const issues = {
    missing_doi: [] as string[],
    missing_title: [] as string[],
    missing_abstract: [] as string[],
    incomplete_metadata: [] as string[],
    suspicious_length: [] as string[],
  };

  papers.forEach((paper) => {
    if (!paper.doi) issues.missing_doi.push(paper.id);
    if (!paper.title) issues.missing_title.push(paper.id);
    if (!paper.abstract) issues.missing_abstract.push(paper.id);
    if (!paper.publication_year) issues.incomplete_metadata.push(paper.id);

    const textLength = paper.full_text?.length || 0;
    if (textLength < 500) {
      issues.suspicious_length.push(paper.id);
    }
  });

  console.log(`📊 Validation Results:`);
  console.log(`  Total papers: ${papers.length}`);
  console.log(`  Missing DOI: ${issues.missing_doi.length}`);
  console.log(`  Missing title: ${issues.missing_title.length}`);
  console.log(`  Missing abstract: ${issues.missing_abstract.length}`);
  console.log(`  Incomplete metadata: ${issues.incomplete_metadata.length}`);
  console.log(`  Suspicious length (<500 chars): ${issues.suspicious_length.length}`);

  // Calculate quality score
  const totalIssues = Object.values(issues).reduce((sum, arr) => sum + arr.length, 0);
  const qualityScore = ((papers.length - totalIssues) / papers.length * 100).toFixed(1);

  console.log(`\n✅ Overall Quality Score: ${qualityScore}%\n`);

  // Recommendations
  if (issues.missing_abstract.length > papers.length * 0.3) {
    console.warn('⚠️  Many papers missing abstracts - consider manual enrichment');
  }
  if (issues.suspicious_length.length > papers.length * 0.2) {
    console.warn('⚠️  Some papers have very short text - check OCR quality');
  }
}

validateIngestedPapers().catch(console.error);
```

