  process.exit(1);
}

const supabase = createClient(SUPABASE_URL, SUPABASE_KEY);

// ============================================================================
// TYPES & INTERFACES
// ============================================================================

interface ExtractedPaperData {
  doi: string | null;
  title: string | null;
  authors: string[];
  publication_year: number | null;
  journal: string | null;
  abstract: string | null;
  full_text: string;
  citations: string[];
  entities: ExtractedEntity[];
  sections: PaperSection[];
  relevance_score: number;
}

interface ExtractedEntity {
  type: 'compound' | 'species' | 'pathogen' | 'nutrient' | 'technique' | 'organism';
  name: string;
  context: string;
  confidence: number;
}

interface PaperSection {
  name: string;
  content: string;
}

interface CrossRefResponse {
  message: {
    DOI: string;
    title: string[];
    author: Array<{ given: string; family: string }>;
    published: { 'date-parts': number[][] };
    'container-title': string[];
    abstract?: string;
  };
}

// ============================================================================
// ENTITY CORPUS FOR CORAL RESEARCH
// ============================================================================

const ENTITY_CORPUS = {
  coral_species: [
    'Acropora', 'Porites', 'Orbicella', 'Montastraea', 'Siderastrea',
    'Goniopora', 'Favia', 'Favites', 'Platygyra', 'Leptoria',
