  results.forEach((result) => {
    const statusIcon =
      result.status === 'PASS' ? '✅' : result.status === 'FAIL' ? '❌' : '⚠️ ';
    console.log(`${statusIcon} ${result.check}`);
    console.log(`   ${result.message}`);
    if (result.details) {
      console.log(`   📌 ${result.details}`);
    }
    console.log('');

    if (result.status === 'PASS') passCount++;
    else if (result.status === 'FAIL') failCount++;
    else warnCount++;
  });

  console.log('═══════════════════════════════════════════════════════════\n');
  console.log('📈 SUMMARY\n');
  console.log(`  ✅ Passed: ${passCount}`);
  console.log(`  ⚠️  Warnings: ${warnCount}`);
  console.log(`  ❌ Failed: ${failCount}`);
  console.log(`  📊 Total: ${results.length}\n`);

  if (failCount === 0) {
    console.log('✅ All critical checks passed! Ready to run: npm run ingest:pdfs\n');
  } else {
    console.log('❌ Some critical checks failed. Please address above issues.\n');
  }

  if (warnCount > 0) {
    console.log('⚠️  Some warnings found. Review above for recommendations.\n');
  }

  console.log('═══════════════════════════════════════════════════════════\n');
}

// Run validation
printResults().catch((error) => {
  console.error('Validation error:', error);
  process.exit(1);
});
