```typescript name=scripts/generate-subject-index.ts
import { createClient } from '@supabase/supabase-js';
import * as fs from 'fs';

async function generateSubjectIndex() {
  const supabase = createClient(
    process.env.SUPABASE_URL!,
    process.env.SUPABASE_SERVICE_KEY!
  );

  console.log('\n');
  console.log('╔════════════════════════════════════════════════════════════╗');
  console.log('║  📚 KNOWLEDGE BASE SUBJECT INDEX GENERATOR                ║');
  console.log('╚════════════════════════════════════════════════════════════╝\n');

  try {
    // Fetch all papers grouped by subject
    const { data: papers, error } = await supabase
      .from('papers')
      .select('id, title, subject_area, file_path, publication_year, doi, relevance_score')
      .order('subject_area')
      .order('publication_year', { ascending: false });

    if (error || !papers) {
      console.error('Error fetching papers:', error);
      return;
    }

    console.log(`📊 Retrieved ${papers.length} papers\n`);

    // Group by subject
    const papersBySubject = new Map<string, typeof papers>();
    papers.forEach((paper) => {
      const subject = paper.subject_area || 'General';
      if (!papersBySubject.has(subject)) {
        papersBySubject.set(subject, []);
      }
      papersBySubject.get(subject)!.push(paper);
    });

    // Generate markdown index
    let indexMarkdown = `# 📚 Knowledge Base Subject Index\n\n`;
    indexMarkdown += `**Total Papers**: ${papers.length}\n`;
    indexMarkdown += `**Subject Categories**: ${papersBySubject.size}\n`;
    indexMarkdown += `**Last Updated**: ${new Date().toISOString()}\n\n`;

    indexMarkdown += `## 📑 Papers by Subject\n\n`;

    for (const [subject, subjectPapers] of papersBySubject) {
      indexMarkdown += `### ${subject}\n\n`;
      indexMarkdown += `**Count**: ${subjectPapers.length} papers\n\n`;

      subjectPapers.forEach((paper: any) => {
        const year = paper.publication_year || 'Unknown';
        const relevance = (paper.relevance_score * 100).toFixed(1);
        const path = paper.file_path ? `(📁 ${paper.file_path})` : '';

        indexMarkdown += `- **${paper.title}**\n`;
        if (paper.doi) {
          indexMarkdown += `  - DOI: [${paper.doi}](https://doi.org/${paper.doi})\n`;
        }
        indexMarkdown += `  - Year: ${year} | Relevance: ${relevance}%\n`;
        if (path) {
          indexMarkdown += `  - ${path}\n`;
        }
        indexMarkdown += `\n`;
      });
    }

    // Write to file
    const indexPath = './docs/science-wiki/subject-index.md';
    fs.writeFileSync(indexPath, indexMarkdown, 'utf-8');

    console.log(`✓ Subject index generated: ${indexPath}`);
    console.log(`✓ Total papers indexed: ${papers.length}`);
    console.log(`✓ Subject categories: ${papersBySubject.size}\n`);

    // Print subject summary
    console.log('📊 SUBJECT SUMMARY:\n');
    for (const [subject, subjectPapers] of papersBySubject) {
      console.log(`  ${subject}: ${subjectPapers.length} papers`);
    }
    console.log('');

  } catch (error) {
    console.error('Error generating subject index:', error);
  }
}

generateSubjectIndex().catch(console.error);
