import * as fs from 'fs';
import * as path from 'path';
import * as pdfParse from 'pdf-parse';
import fetch from 'node-fetch';
import { createClient } from '@supabase/supabase-js';

const supabase = createClient(
  process.env.SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_KEY!
);

// ============================================================================
// TYPES & INTERFACES
// ============================================================================

interface ExtractedMetadata {
  doi: string | null;
  title: string | null;
  authors: string[];
  year: number | null;
  citations: string[];
}

interface CrossRefResult {
  message: {
    DOI: string;
    title: string[];
    author: Array<{ given: string; family: string }>;
    published: { 'date-parts': number[][] };
    'container-title': string[];
  };
}

interface ExtractedEntity {
  type: 'compound' | 'species' | 'pathogen' | 'nutrient';
  name: string;
  context: string;
  confidence: number;
}

interface ChunkedSection {
  section: string;
  content: string;
  subsections?: string[];
}

// ============================================================================
// PDF EXTRACTION & TEXT PROCESSING
// ============================================================================

async function extractPDFsRecursively(startPath: string): Promise<string[]> {
  const pdfPaths: string[] = [];

  function traverse(dirPath: string): void {
    const files = fs.readdirSync(dirPath);

    for (const file of files) {
      const filePath = path.join(dirPath, file);
      const stat = fs.statSync(filePath);

      if (stat.isDirectory()) {
        traverse(filePath);
      } else if (file.toLowerCase().endsWith('.pdf')) {
        pdfPaths.push(filePath);
      }
    }
  }

  traverse(startPath);
  return pdfPaths;
}

async function extractTextFromPDF(filePath: string): Promise<string> {
  try {
    const fileBuffer = fs.readFileSync(filePath);
    const pdfData = await pdfParse(fileBuffer);
    return pdfData.text;
  } catch (error) {
    console.error(`Error extracting PDF ${filePath}:`, error);
    return '';
  }
}

// ============================================================================
// METADATA EXTRACTION (DOI, CITATIONS, AUTHORS)
// ============================================================================

function extractDOI(text: string): string | null {
  // Match DOI patterns: 10.xxxx/xxxxx
  const doiPattern = /\b(10\.\d{4,}\/\S+)\b/gi;
  const matches = text.match(doiPattern);
  return matches ? matches[0] : null;
}

function extractCitations(text: string): string[] {
  // Extract citations in "Author et al. YYYY" format
  const citationPattern = /([A-Z][a-z]+(?:\s+(?:and|&)\s+[A-Z][a-z]+)?(?:\s+et\s+al\.)?)\s+(\d{4})/g;
  const citations: string[] = [];
  let match;

  while ((match = citationPattern.exec(text)) !== null) {
    citations.push(`${match[1]} ${match[2]}`);
  }

  return [...new Set(citations)]; // Remove duplicates
}

function extractAuthorsFromText(text: string): string[] {
  // Extract authors from first 500 chars (usually in header)
  const headerText = text.substring(0, 1500);

  // Look for "Author1, Author2, and Author3" patterns
  const authorPattern = /^([A-Z][a-z]+\s+[A-Z][a-z]+(?:,\s+)?)+/gm;
  const matches = headerText.match(authorPattern);

  if (!matches) return [];

  return matches[0].split(/,\s+and\s+|,\s+/).filter(Boolean);
}

// ============================================================================
// CROSSREF API INTEGRATION
// ============================================================================

async function fetchCrossRefMetadata(doi: string): Promise<Partial<ExtractedMetadata>> {
  try {
    const response = await fetch(`https://api.crossref.org/works/${encodeURIComponent(doi)}`);

    if (!response.ok) {
      console.warn(`CrossRef API error for DOI ${doi}:`, response.status);
      return {};
    }

    const data = (await response.json()) as CrossRefResult;
    const msg = data.message;

    return {
      doi,
      title: msg.title?.[0] || null,
      authors: msg.author
        ? msg.author.map((a) => `${a.given} ${a.family}`)
        : [],
      year: msg.published?.['date-parts']?.[0]?.[0] || null,
      citations: [],
    };
  } catch (error) {
    console.error(`Error fetching CrossRef metadata for ${doi}:`, error);
    return {};
  }
}

// ============================================================================
// NAMED ENTITY RECOGNITION (Chemical NER)
// ============================================================================

// Known coral species names
const CORAL_SPECIES_DICT = [
  'Acropora',
  'Porites',
  'Montipora',
  'Pocillopora',
  'Goniopora',
  'Favia',
  'Favites',
  'Platygyra',
  'Leptoria',
  'Orbicella',
  'Montastraea',
  'Siderastrea',
];

// Known pathogen names
const PATHOGEN_DICT = [
  'SCTLD', // Stony Coral Tissue Loss Disease
  'Black Band Disease',
  'White Plague',
  'Yellow Band Disease',
  'Aspergillosis',
  'Zymovibrio,',
  'Vibrio',
  'Serratia',
];

// Known nutrient/compound names
const COMPOUND_DICT = [
  'Alginate',
  'Chitosan',
  'Calcium',
  'Magnesium',
  'Carbonate',
  'Aragonite',
  'GABA',
  'Dopamine',
  'Serotonin',
  'Histamine',
  'CCA', // Crustose Coralline Algae
  'Bacilli',
  'Probiotics',
];

// SMILES patterns (simplified)
const SMILES_PATTERN = /\b([A-Za-z0-9\[\]()@=\-\\/#]+)\b/g;

function identifyEntities(text: string): ExtractedEntity[] {
  const entities: ExtractedEntity[] = [];
  const words = text.split(/\s+/);

  for (let i = 0; i < words.length; i++) {
    const word = words[i].replace(/[.,;:!?]/g, '');

    // Check coral species
    if (CORAL_SPECIES_DICT.some((s) => word.toLowerCase().includes(s.toLowerCase()))) {
      entities.push({
        type: 'species',
        name: word,
        context: words.slice(Math.max(0, i - 3), i + 4).join(' '),
        confidence: 0.9,
      });
    }

    // Check pathogens
    if (PATHOGEN_DICT.some((p) => word.toLowerCase().includes(p.toLowerCase()))) {
      entities.push({
        type: 'pathogen',
        name: word,
        context: words.slice(Math.max(0, i - 3), i + 4).join(' '),
        confidence: 0.85,
      });
    }

    // Check compounds
    if (COMPOUND_DICT.some((c) => word.toLowerCase().includes(c.toLowerCase()))) {
      entities.push({
        type: 'compound',
        name: word,
        context: words.slice(Math.max(0, i - 3), i + 4).join(' '),
        confidence: 0.8,
      });
    }

    // Check for SMILES-like strings
    if (/[\[\]()@=\-\\/#]/.test(word) && word.length > 3) {
      entities.push({
        type: 'compound',
        name: word,
        context: words.slice(Math.max(0, i - 2), i + 3).join(' '),
        confidence: 0.6,
      });
    }
  }

  return entities;
}

// ============================================================================
// TEXT CHUNKING BY SECTIONS
// ============================================================================

function chunkBySection(text: string): ChunkedSection[] {
  const sections: ChunkedSection[] = [];
  const sectionNames = ['Abstract', 'Introduction', 'Methods', 'Results', 'Discussion', 'Conclusion', 'References'];

  let currentSection = 'Preamble';
  let currentContent = '';

  const lines = text.split('\n');

  for (const line of lines) {
    const sectionMatch = sectionNames.find(
      (s) => line.toUpperCase().includes(s.toUpperCase()) && line.length < 50
    );

    if (sectionMatch) {
      if (currentContent.trim()) {
        sections.push({
          section: currentSection,
          content: currentContent.trim(),
        });
      }
      currentSection = sectionMatch;
      currentContent = '';
    } else {
      currentContent += line + '\n';
    }
  }

  if (currentContent.trim()) {
    sections.push({
      section: currentSection,
      content: currentContent.trim(),
    });
  }

  return sections;
}

// ============================================================================
// DUPLICATE DETECTION
// ============================================================================

async function checkDuplicatePaper(metadata: ExtractedMetadata): Promise<boolean> {
  if (metadata.doi) {
    const { data } = await supabase.from('papers').select('id').eq('doi', metadata.doi);
    if (data && data.length > 0) return true;
  }

  if (metadata.title) {
    const { data } = await supabase
      .from('papers')
      .select('id')
      .ilike('title', `%${metadata.title.substring(0, 50)}%`);
    if (data && data.length > 0) return true;
  }

  return false;
}

// ============================================================================
// DATABASE INSERTION
// ============================================================================

async function insertPaperAndRelated(
  metadata: ExtractedMetadata,
  fullText: string,
  entities: ExtractedEntity[]
): Promise<string | null> {
  try {
    // Insert paper
    const { data: paperData, error: paperError } = await supabase
      .from('papers')
      .insert({
        doi: metadata.doi,
        title: metadata.title,
        authors: metadata.authors,
        publication_year: metadata.year,
        full_text: fullText,
        extracted_text: fullText.substring(0, 50000), // Truncate for storage
      })
      .select('id')
      .single();

    if (paperError || !paperData) {
      console.error('Error inserting paper:', paperError);
      return null;
    }

    const paperId = paperData.id;

    // Insert compounds
    const compounds = entities.filter((e) => e.type === 'compound');
    for (const compound of compounds) {
      const { data: existingCompound } = await supabase
        .from('compounds')
        .select('id')
        .eq('compound_name', compound.name)
        .single();

      let compoundId = existingCompound?.id;

      if (!compoundId) {
        const { data: newCompound } = await supabase
          .from('compounds')
          .insert({
            compound_name: compound.name,
            compound_class: 'Unknown',
          })
          .select('id')
          .single();

        compoundId = newCompound?.id;
      }

      if (compoundId) {
        await supabase.from('paper_compounds').insert({
          paper_id: paperId,
          compound_id: compoundId,
          mention_context: compound.context,
          key_finding: compound.context,
        });
      }
    }

    // Insert pathogens
    const pathogens = entities.filter((e) => e.type === 'pathogen');
    for (const pathogen of pathogens) {
      await supabase.from('pathogens').insert({
        pathogen_name: pathogen.name,
        pathogen_type: 'Unknown',
        host_species: [],
      });
    }

    console.log(`✓ Inserted paper: ${metadata.title}`);
    return paperId;
  } catch (error) {
    console.error('Error inserting paper and related data:', error);
    return null;
  }
}

// ============================================================================
// MAIN INGESTION PIPELINE
// ============================================================================

async function main() {
  const knowledgeFolder = 'C:\\Users\\User\\Documents\\Coralfill\\knowledge';

  console.log('🔍 Scanning for PDFs...');
  const pdfPaths = await extractPDFsRecursively(knowledgeFolder);
  console.log(`Found ${pdfPaths.length} PDFs\n`);

  let successCount = 0;
  let skipCount = 0;
  let errorCount = 0;

  for (const pdfPath of pdfPaths) {
    try {
      console.log(`📄 Processing: ${path.basename(pdfPath)}`);

      // Extract text
      const text = await extractTextFromPDF(pdfPath);
      if (!text) {
        console.warn('⚠ No text extracted');
        errorCount++;
        continue;
      }

      // Extract metadata
      const doi = extractDOI(text);
      let metadata: ExtractedMetadata = {
        doi,
        title: null,
        authors: extractAuthorsFromText(text),
        year: null,
        citations: extractCitations(text),
      };

      // Enrich from CrossRef if DOI exists
      if (doi) {
        const crossRefData = await fetchCrossRefMetadata(doi);
        metadata = { ...metadata, ...crossRefData };
      }

      // Check for duplicates
      if (await checkDuplicatePaper(metadata)) {
        console.log('⊘ Skipped: Duplicate paper');
        skipCount++;
        continue;
      }

      // Extract entities
      const entities = identifyEntities(text);
      console.log(`  Found ${entities.length} entities`);

      // Chunk text
      const chunks = chunkBySection(text);
      console.log(`  Extracted ${chunks.length} sections`);

      // Insert into database
      const paperId = await insertPaperAndRelated(metadata, text, entities);
      if (paperId) {
        successCount++;
      } else {
        errorCount++;
      }
    } catch (error) {
      console.error(`✗ Error processing PDF:`, error);
      errorCount++;
    }

    // Respectful API rate limiting
    await new Promise((resolve) => setTimeout(resolve, 1000));
  }

  console.log(`\n📊 Summary:`);
  console.log(`  ✓ Successfully ingested: ${successCount}`);
  console.log(`  ⊘ Skipped (duplicates): ${skipCount}`);
  console.log(`  ✗ Errors: ${errorCount}`);
}

main().catch(console.error);

