import { createClient } from '@supabase/supabase-js';
import fetch from 'node-fetch';

const supabase = createClient(
  process.env.SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_KEY!
);

const OPENAI_API_KEY = process.env.OPENAI_API_KEY!;
const EMBEDDING_MODEL = 'text-embedding-3-small';
const EMBEDDING_DIMENSION = 1536;
const BATCH_SIZE = 100; // OpenAI batch processing

// ============================================================================
// EMBEDDING GENERATION
// ============================================================================

interface EmbeddingResponse {
  object: string;
  index: number;
  embedding: number[];
}

interface OpenAIEmbeddingResponse {
  object: string;
  data: EmbeddingResponse[];
  model: string;
  usage: {
    prompt_tokens: number;
    total_tokens: number;
  };
}

async function generateEmbeddings(texts: string[]): Promise<number[][]> {
  try {
    const response = await fetch('https://api.openai.com/v1/embeddings', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${OPENAI_API_KEY}`,
      },
      body: JSON.stringify({
        model: EMBEDDING_MODEL,
        input: texts,
        encoding_format: 'float',
      }),
    });

    if (!response.ok) {
      throw new Error(`OpenAI API error: ${response.status}`);
    }

    const data = (await response.json()) as OpenAIEmbeddingResponse;
    return data.data.map((item) => item.embedding);
  } catch (error) {
    console.error('Error generating embeddings:', error);
    throw error;
  }
}

// ============================================================================
// PAPER EMBEDDINGS
// ============================================================================

async function generatePaperEmbeddings() {
  console.log('📖 Generating embeddings for papers...');

  // Fetch all papers without embeddings
  const { data: papers, error } = await supabase
    .from('papers')
    .select('id, title, abstract, extracted_text')
    .is('embedding', null)
    .limit(10000);

  if (error || !papers) {
    console.error('Error fetching papers:', error);
    return;
  }

  console.log(`Found ${papers.length} papers without embeddings`);

  // Process in batches
  for (let i = 0; i < papers.length; i += BATCH_SIZE) {
    const batch = papers.slice(i, i + BATCH_SIZE);
    console.log(`Processing batch ${Math.floor(i / BATCH_SIZE) + 1}/${Math.ceil(papers.length / BATCH_SIZE)}`);

    // Prepare texts for embedding
    const texts = batch.map((paper) => {
      const title = paper.title || '';
      const abstract = paper.abstract || '';
      const content = paper.extracted_text?.substring(0, 3000) || '';
      return `${title}\n\n${abstract}\n\n${content}`.trim();
    });

    try {
      const embeddings = await generateEmbeddings(texts);

      // Update database with embeddings
      for (let j = 0; j < batch.length; j++) {
        const { error: updateError } = await supabase
          .from('papers')
          .update({ embedding: embeddings[j] })
          .eq('id', batch[j].id);

        if (updateError) {
          console.error(`Error updating paper ${batch[j].id}:`, updateError);
        }
      }

      console.log(`✓ Updated ${batch.length} papers`);

      // Rate limiting
      await new Promise((resolve) => setTimeout(resolve, 2000));
    } catch (error) {
      console.error('Error processing batch:', error);
    }
  }

  console.log('✓ Paper embeddings complete');
}

// ============================================================================
// THREAT & CONDITION EMBEDDINGS
// ============================================================================

async function generateThreatEmbeddings() {
  console.log('⚠️ Generating embeddings for threats...');

  const { data: threats, error } = await supabase
    .from('coral_threats')
    .select('id, threat_name, description')
    .is('embedding', null);

  if (error || !threats) {
    console.error('Error fetching threats:', error);
    return;
  }

  const texts = threats.map((threat) => `${threat.threat_name}\n${threat.description || ''}`);

  try {
    const embeddings = await generateEmbeddings(texts);

    for (let i = 0; i < threats.length; i++) {
      await supabase.from('coral_threats').update({ embedding: embeddings[i] }).eq('id', threats[i].id);
    }

    console.log(`✓ Updated ${threats.length} threats`);
  } catch (error) {
    console.error('Error generating threat embeddings:', error);
  }
}

async function generateConditionEmbeddings() {
  console.log('🌡️ Generating embeddings for ideal conditions...');

  const { data: conditions, error } = await supabase
    .from('ideal_conditions')
    .select('id, coral_genus, parameter_name, optimal_value, note');

  if (error || !conditions) {
    console.error('Error fetching conditions:', error);
    return;
  }

  // Note: We don't store embeddings for conditions directly, but for profiles
  console.log('✓ Condition profiles prepared for embedding on-demand');
}

// ============================================================================
// SIMILARITY SEARCH FUNCTION
// ============================================================================

async function similaritySearch(query: string, topK: number = 10) {
  console.log(`🔍 Searching for: "${query}"`);

  // Generate embedding for query
  try {
    const [queryEmbedding] = await generateEmbeddings([query]);

    // Vector similarity search using pgvector
    const { data: results, error } = await supabase.rpc('search_papers_by_embedding', {
      query_embedding: queryEmbedding,
      similarity_threshold: 0.5,
      match_count: topK,
    });

    if (error) {
      console.error('Error searching papers:', error);
      return [];
    }

    return results || [];
  } catch (error) {
    console.error('Error performing similarity search:', error);
    return [];
  }
}

// ============================================================================
// RPC FUNCTION FOR VECTOR SIMILARITY (Execute in Supabase)
// ============================================================================

/*
CREATE OR REPLACE FUNCTION search_papers_by_embedding(
  query_embedding VECTOR(1536),
  similarity_threshold FLOAT DEFAULT 0.5,
  match_count INT DEFAULT 10
)
RETURNS TABLE (
  id UUID,
  title TEXT,
  doi TEXT,
  similarity FLOAT
) AS $$
BEGIN
  RETURN QUERY
  SELECT
    papers.id,
    papers.title,
    papers.doi,
    (papers.embedding <-> query_embedding) * -1 as similarity
  FROM papers
  WHERE papers.embedding IS NOT NULL
    AND (papers.embedding <-> query_embedding) * -1 > similarity_threshold
  ORDER BY papers.embedding <-> query_embedding
  LIMIT match_count;
END;
$$ LANGUAGE plpgsql;
*/

// ============================================================================
// MAIN ORCHESTRATION
// ============================================================================

async function main() {
  console.log('🚀 Starting embedding generation pipeline...\n');

  try {
    await generatePaperEmbeddings();
    await generateThreatEmbeddings();
    await generateConditionEmbeddings();

    console.log('\n✅ All embeddings generated successfully');

    // Example similarity search
    const results = await similaritySearch(
      'oyster shell powder ionic calcium settlement',
      5
    );
    console.log('\nExample search results:', results);
  } catch (error) {
    console.error('Fatal error:', error);
    process.exit(1);
  }
}

main();

