import * as fs from 'fs';
import * as path from 'path';
import { createClient } from '@supabase/supabase-js';

const supabase = createClient(
  process.env.SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_KEY!
);

async function generateWikiIndex() {
  console.log('📚 Generating Wiki Index\n');

  // Fetch all ingested papers
  const { data: papers, error } = await supabase
    .from('papers')
    .select('id, title, authors, publication_year, journal, doi')
    .order('publication_year', { ascending: false })
    .limit(1000);

  if (error || !papers) {
    console.error('Error fetching papers:', error);
    return;
  }

  // Group by year
  const papersByYear = new Map<number, typeof papers>();
  papers.forEach((paper) => {
    const year = paper.publication_year || 0;
    if (!papersByYear.has(year)) {
      papersByYear.set(year, []);
    }
    papersByYear.get(year)!.push(paper);
  });

  // Generate markdown index
  let indexMarkdown = `# Ingested Research Papers Index\n\n`;
  indexMarkdown += `**Total Papers**: ${papers.length}\n\n`;
  indexMarkdown += `*Last Updated*: ${new Date().toISOString()}\n\n`;

  indexMarkdown += `## 📑 Papers by Year\n\n`;

  Array.from(papersByYear.entries())
    .sort((a, b) => b[0] - a[0])
    .forEach(([year, yearPapers]) => {
      indexMarkdown += `### ${year}\n\n`;

      yearPapers.forEach((paper) => {
        const authors = paper.authors?.[0] ? `${paper.authors[0]} et al.` : 'Unknown';
        const doi = paper.doi ? `[DOI](https://doi.org/${paper.doi})` : '';
        const link = `[ingested-papers/${paper.id}](./ingested-papers/${paper.id}.md)`;

        indexMarkdown += `- **${paper.title}** ${link}\n`;
        indexMarkdown += `  - ${authors} (${paper.journal || 'Unknown'})\n`;
        if (doi) indexMarkdown += `  - ${doi}\n`;
        indexMarkdown += `\n`;
      });
    });

  // Write to file
  const indexPath = './docs/science-wiki/ingested-papers-index.md';
  fs.writeFileSync(indexPath, indexMarkdown, 'utf-8');

  console.log(`✓ Wiki index generated: ${indexPath}`);
  console.log(`✓ Total papers indexed: ${papers.length}`);
}

generateWikiIndex().catch(console.error);

