import { createClient } from '@supabase/supabase-js';

const supabase = createClient(
  process.env.SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_KEY!
);

async function validateIngestedPapers() {
  console.log('🔍 Validating Ingested Papers\n');

  const { data: papers, error } = await supabase
    .from('papers')
    .select('id, title, doi, abstract, full_text, publication_year')
    .limit(1000);

  if (error || !papers) {
    console.error('Error fetching papers:', error);
    return;
  }

  const issues = {
    missing_doi: [] as string[],
    missing_title: [] as string[],
    missing_abstract: [] as string[],
    incomplete_metadata: [] as string[],
    suspicious_length: [] as string[],
  };

  papers.forEach((paper) => {
    if (!paper.doi) issues.missing_doi.push(paper.id);
    if (!paper.title) issues.missing_title.push(paper.id);
    if (!paper.abstract) issues.missing_abstract.push(paper.id);
    if (!paper.publication_year) issues.incomplete_metadata.push(paper.id);

    const textLength = paper.full_text?.length || 0;
    if (textLength < 500) {
      issues.suspicious_length.push(paper.id);
    }
  });

  console.log(`📊 Validation Results:`);
  console.log(`  Total papers: ${papers.length}`);
  console.log(`  Missing DOI: ${issues.missing_doi.length}`);
  console.log(`  Missing title: ${issues.missing_title.length}`);
  console.log(`  Missing abstract: ${issues.missing_abstract.length}`);
  console.log(`  Incomplete metadata: ${issues.incomplete_metadata.length}`);
  console.log(`  Suspicious length (<500 chars): ${issues.suspicious_length.length}`);

  // Calculate quality score
  const totalIssues = Object.values(issues).reduce((sum, arr) => sum + arr.length, 0);
  const qualityScore = ((papers.length - totalIssues) / papers.length * 100).toFixed(1);

  console.log(`\n✅ Overall Quality Score: ${qualityScore}%\n`);

  // Recommendations
  if (issues.missing_abstract.length > papers.length * 0.3) {
    console.warn('⚠️  Many papers missing abstracts - consider manual enrichment');
  }
  if (issues.suspicious_length.length > papers.length * 0.2) {
    console.warn('⚠️  Some papers have very short text - check OCR quality');
  }
}

validateIngestedPapers().catch(console.error);

