  printSuccess(title: string, entities: number, species: number, compounds: number, relevance: number, wiki: string) {
    console.log('  ✓ Successfully ingested');
    console.log(`    Title: ${title.substring(0, 60)}${title.length > 60 ? '...' : ''}`);
