    console.log(`  ⏱️  Avg per PDF: ${this.stats.avgTimePerPDF.toFixed(1)}s\n`);

    console.log('╔════════════════════════════════════════════════════════════╗');
    console.log('║  ✅ PIPELINE COMPLETE                                      ║');
    console.log('╚════════════════════════════════════════════════════════════╝\n');
