#!/usr/bin/env ts-node

import * as fs from 'fs';
import * as path from 'path';
import { createClient } from '@supabase/supabase-js';

interface ValidationResult {
  check: string;
  status: 'PASS' | 'FAIL' | 'WARN';
  message: string;
  details?: string;
}

const results: ValidationResult[] = [];

// ============================================================================
// 1. ENVIRONMENT VALIDATION
// ============================================================================

console.log('\n╔════════════════════════════════════════════════════════════╗');
console.log('║  🔍 CORALFILL SYSTEM VALIDATION & DIAGNOSTICS             ║');
console.log('╚════════════════════════════════════════════════════════════╝\n');

console.log('📋 Step 1: Environment Validation\n');

// Check .env file
if (fs.existsSync('.env')) {
  results.push({
    check: '.env file exists',
    status: 'PASS',
    message: '✅ .env file found',
  });

  // Read and validate .env contents
  const envContent = fs.readFileSync('.env', 'utf-8');
  const hasSupabaseUrl = envContent.includes('SUPABASE_URL');
  const hasSupabaseKey = envContent.includes('SUPABASE_SERVICE_KEY');

  if (hasSupabaseUrl && hasSupabaseKey) {
    results.push({
      check: '.env has required Supabase credentials',
      status: 'PASS',
      message: '✅ Supabase credentials configured',
    });
  } else {
    results.push({
      check: '.env has required Supabase credentials',
      status: 'FAIL',
      message: '❌ Missing SUPABASE_URL or SUPABASE_SERVICE_KEY',
      details: 'Run: cp .env.example .env && edit with your credentials',
    });
  }
} else {
  results.push({
    check: '.env file exists',
    status: 'FAIL',
    message: '❌ .env file not found',
    details: 'Run: cp .env.example .env',
  });
}

// Check package.json
if (fs.existsSync('package.json')) {
  results.push({
    check: 'package.json exists',
    status: 'PASS',
    message: '✅ package.json found',
  });
} else {
  results.push({
    check: 'package.json exists',
    status: 'FAIL',
    message: '❌ package.json not found',
  });
}

// Check node_modules
if (fs.existsSync('node_modules')) {
  results.push({
    check: 'Dependencies installed',
    status: 'PASS',
    message: '✅ node_modules directory exists',
  });
} else {
  results.push({
    check: 'Dependencies installed',
    status: 'WARN',
    message: '⚠️  node_modules not found',
    details: 'Run: npm install',
  });
}

// ============================================================================
// 2. FILE SYSTEM VALIDATION
// ============================================================================

console.log('\n📁 Step 2: File System Validation\n');

const knowledgeDir = 'C:\\Users\\User\\Documents\\Coralfill\\Knowledge';
if (fs.existsSync(knowledgeDir)) {
  const files = fs.readdirSync(knowledgeDir);
  const pdfCount = files.filter((f) => f.toLowerCase().endsWith('.pdf')).length;

  results.push({
    check: 'Knowledge directory exists',
    status: 'PASS',
    message: `✅ Found: ${knowledgeDir}`,
    details: `Contains ${pdfCount} PDF files`,
  });
} else {
  results.push({
    check: 'Knowledge directory exists',
    status: 'WARN',
    message: `⚠️  Directory not found: ${knowledgeDir}`,
    details: 'Create directory and add PDF files to start ingestion',
  });
}

// Check wiki output directory
const wikiDir = './docs/science-wiki/ingested-papers';
if (fs.existsSync(wikiDir)) {
  const wikiFiles = fs.readdirSync(wikiDir);
  results.push({
    check: 'Wiki output directory',
    status: 'PASS',
    message: `✅ Wiki directory exists with ${wikiFiles.length} files`,
  });
} else {
  results.push({
    check: 'Wiki output directory',
    status: 'WARN',
    message: '⚠️  Wiki directory will be created on first run',
  });
}

// Check pipeline file
if (fs.existsSync('pdf-ingestion-pipeline.ts')) {
  results.push({
    check: 'Pipeline file exists',
    status: 'PASS',
    message: '✅ pdf-ingestion-pipeline.ts found',
  });
} else {
  results.push({
    check: 'Pipeline file exists',
    status: 'FAIL',
    message: '❌ pdf-ingestion-pipeline.ts not found',
  });
}

// ============================================================================
// 3. TYPESCRIPT & NODE VALIDATION
// ============================================================================

console.log('\n🔧 Step 3: Build Tools Validation\n');

// Check tsconfig.json
if (fs.existsSync('tsconfig.json')) {
  results.push({
    check: 'TypeScript config',
    status: 'PASS',
    message: '✅ tsconfig.json found',
  });
} else {
  results.push({
    check: 'TypeScript config',
    status: 'WARN',
    message: '⚠️  tsconfig.json not found (will use defaults)',
  });
}

// Node version check
const nodeVersion = process.version;
results.push({
  check: 'Node.js version',
  status: 'PASS',
  message: `✅ ${nodeVersion}`,
  details: 'Recommended: v16.0.0 or higher',
});

// ============================================================================
// 4. SUPABASE CONNECTION TEST (async)
// ============================================================================

async function testSupabaseConnection() {
  console.log('\n🗄️  Step 4: Supabase Connection Test\n');

  const supabaseUrl = process.env.SUPABASE_URL;
  const supabaseKey = process.env.SUPABASE_SERVICE_KEY;

  if (!supabaseUrl || !supabaseKey) {
    results.push({
      check: 'Supabase credentials',
      status: 'FAIL',
      message: '❌ Missing SUPABASE_URL or SUPABASE_SERVICE_KEY',
      details: 'Set these in your .env file',
    });
    return;
  }

  try {
    const supabase = createClient(supabaseUrl, supabaseKey);

    // Test auth
    const { data, error } = await supabase.auth.getSession();

    results.push({
      check: 'Supabase connection',
      status: 'PASS',
      message: '✅ Connected to Supabase',
      details: supabaseUrl,
    });

    // Test database access
    try {
      const { count, error: countError } = await supabase
        .from('papers')
        .select('id', { count: 'exact', head: true });

      if (!countError) {
        results.push({
          check: 'Database tables accessible',
          status: 'PASS',
          message: `✅ Papers table has ${count || 0} records`,
        });
      } else {
        results.push({
          check: 'Database tables accessible',
          status: 'WARN',
          message: '⚠️  Could not query papers table',
          details: countError.message,
        });
      }
    } catch (tableError) {
      results.push({
        check: 'Database tables accessible',
        status: 'WARN',
        message: '⚠️  Tables may not exist yet',
        details: 'Run SQL migrations first',
      });
    }
  } catch (error) {
    results.push({
      check: 'Supabase connection',
      status: 'FAIL',
      message: '❌ Failed to connect to Supabase',
      details: error instanceof Error ? error.message : 'Unknown error',
    });
  }
}

// ============================================================================
// 5. DEPENDENCIES CHECK
// ============================================================================

console.log('\n📦 Step 5: Dependencies Check\n');

const requiredDeps = [
  'pdf-parse',
  '@supabase/supabase-js',
  'node-fetch',
  'ts-node',
  'typescript',
];

if (fs.existsSync('package.json')) {
  const packageJson = JSON.parse(fs.readFileSync('package.json', 'utf-8'));
  const allDeps = {
    ...packageJson.dependencies,
    ...packageJson.devDependencies,
  };

  requiredDeps.forEach((dep) => {
    if (allDeps[dep]) {
      results.push({
        check: `Dependency: ${dep}`,
        status: 'PASS',
        message: `✅ ${dep} v${allDeps[dep]}`,
      });
    } else {
      results.push({
        check: `Dependency: ${dep}`,
        status: 'FAIL',
        message: `❌ ${dep} not installed`,
        details: 'Run: npm install',
      });
    }
  });
}

// ============================================================================
// 6. SCRIPTS AVAILABILITY
// ============================================================================

console.log('\n🚀 Step 6: Available Scripts\n');

const scripts = [
  'ingest:pdfs',
  'ingest:pdfs:watch',
  'generate:wiki',
  'validate:papers',
];

if (fs.existsSync('package.json')) {
  const packageJson = JSON.parse(fs.readFileSync('package.json', 'utf-8'));
  const availableScripts = packageJson.scripts || {};

  scripts.forEach((script) => {
    if (availableScripts[script]) {
      results.push({
        check: `Script: ${script}`,
        status: 'PASS',
        message: `✅ npm run ${script}`,
      });
    } else {
      results.push({
        check: `Script: ${script}`,
        status: 'WARN',
        message: `⚠️  Script not found: ${script}`,
      });
    }
  });
}

// ============================================================================
// 7. PRINT RESULTS
// ============================================================================

async function printResults() {
  await testSupabaseConnection();

  console.log('\n═══════════════════════════════════════════════════════════\n');
  console.log('📊 VALIDATION RESULTS\n');

  let passCount = 0;
  let failCount = 0;
  let warnCount = 0;

  results.forEach((result) => {
    const statusIcon =
      result.status === 'PASS' ? '✅' : result.status === 'FAIL' ? '❌' : '⚠️ ';
    console.log(`${statusIcon} ${result.check}`);
    console.log(`   ${result.message}`);
    if (result.details) {
      console.log(`   📌 ${result.details}`);
    }
    console.log('');

    if (result.status === 'PASS') passCount++;
    else if (result.status === 'FAIL') failCount++;
    else warnCount++;
  });

  console.log('═══════════════════════════════════════════════════════════\n');
  console.log('📈 SUMMARY\n');
  console.log(`  ✅ Passed: ${passCount}`);
  console.log(`  ⚠️  Warnings: ${warnCount}`);
  console.log(`  ❌ Failed: ${failCount}`);
  console.log(`  📊 Total: ${results.length}\n`);

  if (failCount === 0) {
    console.log('✅ All critical checks passed! Ready to run: npm run ingest:pdfs\n');
  } else {
    console.log('❌ Some critical checks failed. Please address above issues.\n');
  }

  if (warnCount > 0) {
    console.log('⚠️  Some warnings found. Review above for recommendations.\n');
  }

  console.log('═══════════════════════════════════════════════════════════\n');
}

// Run validation
printResults().catch((error) => {
  console.error('Validation error:', error);
  process.exit(1);
});

