import { createClient } from '@supabase/supabase-js';
import * as fs from 'fs';

async function validatePapers() {
  const supabaseUrl = process.env.SUPABASE_URL || '';
  const supabaseKey = process.env.SUPABASE_SERVICE_KEY || '';

  if (!supabaseUrl || !supabaseKey) {
    console.error('❌ Missing Supabase credentials in .env');
    process.exit(1);
  }

  const supabase = createClient(supabaseUrl, supabaseKey);

  console.log('\n╔════════════════════════════════════════════════════════════╗');
  console.log('║  📊 DATA VALIDATION REPORT                                ║');
  console.log('╚════════════════════════════════════════════════════════════╝\n');

  try {
    // Fetch all papers
    const { data: papers, error: papersError, count: papersCount } = await supabase
      .from('papers')
      .select('id, title, doi, abstract, full_text, publication_year', { count: 'exact' });

    if (papersError) {
      console.error('Error fetching papers:', papersError);
      return;
    }

    console.log('📄 PAPERS ANALYSIS\n');
    console.log(`  Total papers: ${papersCount}\n`);

    let issues = {
      missing_doi: 0,
      missing_title: 0,
      missing_abstract: 0,
      missing_year: 0,
      short_text: 0,
    };

    if (papers) {
      papers.forEach((paper: any) => {
        if (!paper.doi) issues.missing_doi++;
        if (!paper.title) issues.missing_title++;
        if (!paper.abstract) issues.missing_abstract++;
        if (!paper.publication_year) issues.missing_year++;
        if (!paper.full_text || paper.full_text.length < 500) issues.short_text++;
      });
    }

    console.log('⚠️  DATA QUALITY ISSUES\n');
    console.log(`  Missing DOI: ${issues.missing_doi}/${papersCount}`);
    console.log(`  Missing title: ${issues.missing_title}/${papersCount}`);
    console.log(`  Missing abstract: ${issues.missing_abstract}/${papersCount}`);
    console.log(`  Missing year: ${issues.missing_year}/${papersCount}`);
    console.log(`  Short text (<500 chars): ${issues.short_text}/${papersCount}\n`);

    // Fetch compounds
    const { data: compounds, count: compoundsCount } = await supabase
      .from('compounds')
      .select('id', { count: 'exact' });

    console.log('🧪 COMPOUNDS\n');
    console.log(`  Total compounds: ${compoundsCount}\n`);

    // Fetch pathogens
    const { data: pathogens, count: pathogensCount } = await supabase
      .from('pathogens')
      .select('id', { count: 'exact' });

    console.log('⚠️  PATHOGENS\n');
    console.log(`  Total pathogens: ${pathogensCount}\n`);

    // Fetch relationships
    const { data: paperCompounds, count: relationshipCount } = await supabase
      .from('paper_compounds')
      .select('id', { count: 'exact' });

    console.log('🔗 RELATIONSHIPS\n');
    console.log(`  Paper-Compound links: ${relationshipCount}\n`);

    // Calculate quality score
    const totalIssues = Object.values(issues).reduce((a, b) => a + b, 0);
    const qualityScore = papersCount > 0 ? ((papersCount * 5 - totalIssues) / (papersCount * 5)) * 100 : 0;

    console.log('═══════════════════════════════════════════════════════════\n');
    console.log('📊 OVERALL STATISTICS\n');
    console.log(`  Papers: ${papersCount}`);
    console.log(`  Compounds: ${compoundsCount}`);
    console.log(`  Pathogens: ${pathogensCount}`);
    console.log(`  Relationships: ${relationshipCount}`);
    console.log(`  Total Issues: ${totalIssues}`);
    console.log(`  Quality Score: ${qualityScore.toFixed(1)}%\n`);

    if (qualityScore >= 95) {
      console.log('✅ EXCELLENT quality - All systems go!\n');
    } else if (qualityScore >= 85) {
      console.log('✅ GOOD quality - Minor issues detected\n');
    } else if (qualityScore >= 70) {
      console.log('⚠️  ACCEPTABLE quality - Review recommendations\n');
    } else {
      console.log('❌ POOR quality - Address issues before using in production\n');
    }

    console.log('═══════════════════════════════════════════════════════════\n');

  } catch (error) {
    console.error('Validation error:', error);
  }
}

validatePapers().catch((error) => {
  console.error('Fatal error:', error);
  process.exit(1);
});

