import * as fs from 'fs';
import * as path from 'path';
import * as pdfParse from 'pdf-parse';
import fetch from 'node-fetch';
import { createClient } from '@supabase/supabase-js';

// ============================================================================
// CONFIGURATION
// ============================================================================

const KNOWLEDGE_BASE_DIR = 'C:\\Users\\User\\Documents\\Coralfill\\Knowledge';
const WIKI_OUTPUT_DIR = './docs/science-wiki/ingested-papers';
const SUPABASE_URL = process.env.SUPABASE_URL || '';
const SUPABASE_KEY = process.env.SUPABASE_SERVICE_KEY || '';
const CROSSREF_EMAIL = process.env.CROSSREF_EMAIL || 'research@coralfil.org';

if (!SUPABASE_URL || !SUPABASE_KEY) {
  console.error('❌ Error: SUPABASE_URL and SUPABASE_SERVICE_KEY must be set in .env file');
  process.exit(1);
}

const supabase = createClient(SUPABASE_URL, SUPABASE_KEY);

// ============================================================================
// TYPES & INTERFACES
// ============================================================================

interface ExtractedPaperData {
  doi: string | null;
  title: string | null;
  authors: string[];
  publication_year: number | null;
  journal: string | null;
  abstract: string | null;
  full_text: string;
  citations: string[];
  entities: ExtractedEntity[];
  sections: PaperSection[];
  relevance_score: number;
  subject_area: string; // NEW: Track subject/category
  file_path: string; // NEW: Original file path
  relative_path: string; // NEW: Path relative to Knowledge dir
}

interface ExtractedEntity {
  type: 'compound' | 'species' | 'pathogen' | 'nutrient' | 'technique' | 'organism';
  name: string;
  context: string;
  confidence: number;
}

interface PaperSection {
  name: string;
  content: string;
}

interface DirectoryStats {
  directory: string;
  subject: string;
  pdfCount: number;
  successCount: number;
  skipCount: number;
  errorCount: number;
  totalTime: number;
}

// ============================================================================
// ENTITY CORPUS
// ============================================================================

const ENTITY_CORPUS = {
  coral_species: [
    'Acropora', 'Porites', 'Orbicella', 'Montastraea', 'Siderastrea',
    'Goniopora', 'Favia', 'Favites', 'Platygyra', 'Leptoria',
    'Pocillopora', 'Montipora', 'Stylophora', 'Seriatopora',
    'Pavona', 'Leptoseris', 'Fungia', 'Cyphastrea', 'Lobophyllia'
  ],

  pathogens: [
    'SCTLD', 'Black Band Disease', 'White Plague', 'Yellow Band Disease',
    'Aspergillosis', 'Vibrio', 'Serratia', 'Zymovibrio',
    'Coral Bleaching', 'Thermal Stress', 'Disease', 'Pathogen',
    'Bacterial', 'Fungal', 'Viral', 'Infection'
  ],

  compounds_and_materials: [
    'Alginate', 'Chitosan', 'Oyster shell', 'Calcium', 'Magnesium',
    'Carbonate', 'Aragonite', 'GABA', 'Dopamine', 'Glutamic acid',
    'Serotonin', 'Histamine', 'CCA', 'Coralline algae', 'Bacillus',
    'Probiotics', 'Biofilm', 'Hydrogel', 'Polymer', 'Microarchitecture',
    'Geopolymer', '3D-printed', '3D printing', 'Biodegradable',
    'Mineral Accretion', 'MAT', 'Electrical stimulation', 'Arginine',
    'Lysine', 'Settlement cue', 'Larval cue'
  ],

  techniques: [
    'settlement assay', 'PAM fluorometry', 'qPCR', 'sequencing',
    'metabolomic', 'proteomic', 'transcriptomic', 'omics',
    'thermal tolerance', 'bleaching', 'reproduction', 'spawning',
    'larval competency', 'fertilization', 'hatchery', 'restoration',
    'aquaculture', 'nursery', 'transplantation', 'monitoring'
  ],

  coral_processes: [
    'Settlement', 'Metamorphosis', 'Calcification', 'Photosynthesis',
    'Symbiosis', 'Zooxanthellae', 'Bleaching', 'Recovery',
    'Growth', 'Reproduction', 'Spawning', 'Fertilization',
    'Larval development', 'Competency', 'Recruitment', 'Mortality'
  ]
};

// ============================================================================
// UTILITY: RECURSIVE PDF DISCOVERY WITH HIERARCHY
// ============================================================================

interface PDFFile {
  path: string;
  relativePath: string;
  subject: string;
}

function findAllPDFsWithHierarchy(dirPath: string, baseDir: string = dirPath): PDFFile[] {
  const pdfFiles: PDFFile[] = [];

  function traverse(currentPath: string): void {
    try {
      const items = fs.readdirSync(currentPath);

      for (const item of items) {
        const fullPath = path.join(currentPath, item);
        try {
          const stat = fs.statSync(fullPath);

          if (stat.isDirectory()) {
            traverse(fullPath);
          } else if (item.toLowerCase().endsWith('.pdf')) {
            const relativePath = path.relative(baseDir, fullPath);
            const subject = path.dirname(relativePath).split(path.sep)[0] || 'root';

            pdfFiles.push({
              path: fullPath,
              relativePath,
              subject,
            });
          }
        } catch (err) {
          continue;
        }
      }
    } catch (err) {
      console.warn(`Could not read directory: ${currentPath}`);
    }
  }

  traverse(dirPath);
  return pdfFiles;
}

// ============================================================================
// PDF TEXT EXTRACTION
// ============================================================================

async function extractTextFromPDF(filePath: string): Promise<string> {
  try {
    const fileBuffer = fs.readFileSync(filePath);
    const pdfData = await pdfParse(fileBuffer);
    return pdfData.text;
  } catch (error) {
    console.error(`  Error extracting PDF: ${error instanceof Error ? error.message : 'Unknown error'}`);
    return '';
  }
}

// ============================================================================
// METADATA EXTRACTION
// ============================================================================

function extractDOI(text: string): string | null {
  const doiPattern = /\b(10\.\d{4,}\/[^\s]+)\b/gi;
  const matches = text.match(doiPattern);
  return matches ? matches[0].toLowerCase() : null;
}

function extractCitations(text: string): string[] {
  const citationPattern = /([A-Z][a-z]+(?:\s+(?:and|&)\s+[A-Z][a-z]+)?(?:\s+et\s+al\.)?)\s+(\d{4})/g;
  const citations: string[] = [];
  let match;

  while ((match = citationPattern.exec(text)) !== null) {
    citations.push(`${match[1]} ${match[2]}`);
  }

  return [...new Set(citations)];
}

function extractAuthorsFromHeader(text: string): string[] {
  const headerText = text.substring(0, 2000);
  const authorPattern = /^([A-Z][a-z]+\s+[A-Z][a-z\.]*(?:,\s*)?)+/gm;
  const match = headerText.match(authorPattern);

  if (!match) return [];

  return match[0]
    .split(/,\s+and\s+|,\s+|\s+and\s+/)
    .filter((a) => a && a.trim().length > 2 && a.trim().length < 100)
    .slice(0, 10);
}

function extractYearFromText(text: string): number | null {
  const yearPattern = /\b(19|20)\d{2}\b/;
  const match = text.match(yearPattern);
  return match ? parseInt(match[0]) : null;
}

// ============================================================================
// CROSSREF API METADATA ENRICHMENT
// ============================================================================

async function fetchCrossRefMetadata(doi: string): Promise<Partial<ExtractedPaperData>> {
  try {
    const url = `https://api.crossref.org/works/${encodeURIComponent(doi)}`;
    const response = await fetch(url, {
      headers: { 'mailto': CROSSREF_EMAIL }
    });

    if (!response.ok) {
      return {};
    }

    const data = (await response.json()) as any;
    const msg = data.message;

    return {
      doi,
      title: msg.title?.[0] || null,
      authors: msg.author
        ? msg.author.map((a: any) => `${a.given || ''} ${a.family || ''}`.trim()).filter((n: string) => n.length > 0)
        : [],
      publication_year: msg.published?.['date-parts']?.[0]?.[0] || null,
      journal: msg['container-title']?.[0] || null,
      abstract: msg.abstract || null,
    };
  } catch (error) {
    return {};
  }
}

// ============================================================================
// ENTITY EXTRACTION
// ============================================================================

function extractEntities(text: string): ExtractedEntity[] {
  const entities: ExtractedEntity[] = [];
  const words = text.split(/[\s\n]+/);

  for (let i = 0; i < words.length; i++) {
    const word = words[i].replace(/[.,;:!?()\[\]{}]/g, '');
    const lowerWord = word.toLowerCase();
    const context = words.slice(Math.max(0, i - 5), Math.min(words.length, i + 6)).join(' ');

    if (ENTITY_CORPUS.coral_species.some((s) => lowerWord.includes(s.toLowerCase()))) {
      entities.push({
        type: 'species',
        name: word,
        context,
        confidence: 0.9,
      });
    }

    if (ENTITY_CORPUS.pathogens.some((p) => lowerWord.includes(p.toLowerCase()))) {
      entities.push({
        type: 'pathogen',
        name: word,
        context,
        confidence: 0.85,
      });
    }

    if (ENTITY_CORPUS.compounds_and_materials.some((c) => lowerWord.includes(c.toLowerCase()))) {
      entities.push({
        type: 'compound',
        name: word,
        context,
        confidence: 0.8,
      });
    }

    if (ENTITY_CORPUS.techniques.some((t) => lowerWord.includes(t.toLowerCase()))) {
      entities.push({
        type: 'technique',
        name: word,
        context,
        confidence: 0.75,
      });
    }

    if (ENTITY_CORPUS.coral_processes.some((p) => lowerWord.includes(p.toLowerCase()))) {
      entities.push({
        type: 'organism',
        name: word,
        context,
        confidence: 0.7,
      });
    }
  }

  const uniqueEntities = new Map<string, ExtractedEntity>();
  entities.forEach((e) => {
    const key = `${e.type}:${e.name.toLowerCase()}`;
    if (!uniqueEntities.has(key)) {
      uniqueEntities.set(key, e);
    }
  });

  return Array.from(uniqueEntities.values()).slice(0, 100);
}

// ============================================================================
// SECTION EXTRACTION
// ============================================================================

function extractSections(text: string): PaperSection[] {
  const sections: PaperSection[] = [];
  const sectionNames = [
    'Abstract', 'Introduction', 'Methods', 'Materials and Methods',
    'Results', 'Discussion', 'Conclusion', 'Conclusions',
    'References', 'Acknowledgments'
  ];

  let currentSection = 'Preamble';
  let currentContent = '';

  const lines = text.split('\n');

  for (const line of lines) {
    const sectionMatch = sectionNames.find(
      (s) => line.toUpperCase().includes(s.toUpperCase()) && line.length < 60
    );

    if (sectionMatch && currentContent.trim().length > 50) {
      sections.push({
        name: currentSection,
        content: currentContent.trim(),
      });
      currentSection = sectionMatch;
      currentContent = '';
    } else {
      currentContent += line + '\n';
    }
  }

  if (currentContent.trim()) {
    sections.push({
      name: currentSection,
      content: currentContent.trim(),
    });
  }

  return sections;
}

// ============================================================================
// RELEVANCE SCORING
// ============================================================================

function scoreRelevanceForCoralResearch(text: string): number {
  const coralKeywords = [
    'coral', 'reef', 'bleaching', 'settlement', 'larvae', 'larval',
    'restoration', 'aquaculture', 'reproduction', 'spawning',
    'symbiosis', 'zooxanthellae', 'thermal', 'acidification',
    'conservation', 'chitosan', 'alginate', 'probiotic', 'disease',
    'calcification', 'photosynthesis', 'symbiont'
  ];

  const textLower = text.toLowerCase();
  const matchCount = coralKeywords.filter((kw) => textLower.includes(kw)).length;

  return Math.min(1, matchCount / coralKeywords.length);
}

// ============================================================================
// DUPLICATE DETECTION
// ============================================================================

async function checkDuplicatePaper(metadata: Partial<ExtractedPaperData>): Promise<boolean> {
  if (metadata.doi) {
    const { data } = await supabase
      .from('papers')
      .select('id')
      .eq('doi', metadata.doi)
      .limit(1);
    if (data && data.length > 0) return true;
  }

  if (metadata.title) {
    const titleSnippet = metadata.title.substring(0, 50);
    const { data } = await supabase
      .from('papers')
      .select('id')
      .ilike('title', `%${titleSnippet}%`)
      .limit(1);
    if (data && data.length > 0) return true;
  }

  return false;
}

// ============================================================================
// DATABASE INSERTION
// ============================================================================

async function insertPaperAndRelatedData(
  metadata: ExtractedPaperData
): Promise<string | null> {
  try {
    const { data: paperData, error: paperError } = await supabase
      .from('papers')
      .insert({
        doi: metadata.doi,
        title: metadata.title || `Untitled (${path.basename(metadata.file_path)})`,
        authors: metadata.authors,
        publication_year: metadata.publication_year,
        journal: metadata.journal,
        abstract: metadata.abstract,
        full_text: metadata.full_text,
        extracted_text: metadata.full_text.substring(0, 50000),
        subject_area: metadata.subject_area, // NEW: Store subject
        file_path: metadata.relative_path, // NEW: Store relative path
      })
      .select('id')
      .single();

    if (paperError || !paperData) {
      console.error('  Database insert error:', paperError);
      return null;
    }

    const paperId = paperData.id;

    // Insert compounds
    const compounds = metadata.entities.filter((e) => e.type === 'compound');
    for (const compound of [...new Set(compounds.map((c) => c.name))]) {
      try {
        const { data: existingCompound } = await supabase
          .from('compounds')
          .select('id')
          .eq('compound_name', compound)
          .single();

        let compoundId = existingCompound?.id;

        if (!compoundId) {
          const { data: newCompound } = await supabase
            .from('compounds')
            .insert({
              compound_name: compound,
              compound_class: 'Unknown',
            })
            .select('id')
            .single();
          compoundId = newCompound?.id;
        }

        if (compoundId) {
          await supabase.from('paper_compounds').insert({
            paper_id: paperId,
            compound_id: compoundId,
            mention_context: compound,
            key_finding: compound,
          });
        }
      } catch (err) {
        // Skip on constraint violation
      }
    }

    // Insert pathogens
    const pathogens = metadata.entities.filter((e) => e.type === 'pathogen');
    for (const pathogen of [...new Set(pathogens.map((p) => p.name))]) {
      try {
        const { data: existingPathogen } = await supabase
          .from('pathogens')
          .select('id')
          .eq('pathogen_name', pathogen)
          .single();

        if (!existingPathogen) {
          await supabase.from('pathogens').insert({
            pathogen_name: pathogen,
            pathogen_type: 'Unknown',
            host_species: [],
          });
        }
      } catch (err) {
        // Skip on constraint violation
      }
    }

    return paperId;
  } catch (error) {
    console.error('  Insertion error:', error instanceof Error ? error.message : error);
    return null;
  }
}

// ============================================================================
// WIKI MARKDOWN GENERATION
// ============================================================================

function generateWikiMarkdown(metadata: ExtractedPaperData, paperId: string): string {
  let markdown = `# ${metadata.title || 'Untitled Paper'}\n\n`;
  markdown += `**Database ID**: \`${paperId}\`\n\n`;
  markdown += `**Subject Area**: ${metadata.subject_area}\n\n`;
  markdown += `**File Path**: \`${metadata.relative_path}\`\n\n`;
  markdown += `**DOI**: ${metadata.doi ? `[${metadata.doi}](https://doi.org/${metadata.doi})` : 'Not available'}\n\n`;
  markdown += `**Authors**: ${metadata.authors.join(', ') || 'Unknown'}\n\n`;
  markdown += `**Year**: ${metadata.publication_year || 'Unknown'}\n\n`;
  markdown += `**Journal**: ${metadata.journal || 'Unknown'}\n\n`;
  markdown += `**Relevance Score**: ${(metadata.relevance_score * 100).toFixed(1)}%\n\n`;

  if (metadata.abstract) {
    markdown += `## Abstract\n\n${metadata.abstract}\n\n`;
  }

  const species = [...new Set(metadata.entities.filter((e) => e.type === 'species').map((e) => e.name))];
  if (species.length > 0) {
    markdown += `## 🐠 Coral Species Mentioned\n\n${species.map((s) => `- ${s}`).join('\n')}\n\n`;
  }

  const compounds = [...new Set(metadata.entities.filter((e) => e.type === 'compound').map((e) => e.name))];
  if (compounds.length > 0) {
    markdown += `## 🧪 Compounds & Materials\n\n${compounds.map((c) => `- ${c}`).join('\n')}\n\n`;
  }

  const pathogens = [...new Set(metadata.entities.filter((e) => e.type === 'pathogen').map((e) => e.name))];
  if (pathogens.length > 0) {
    markdown += `## ⚠️ Pathogens & Threats\n\n${pathogens.map((p) => `- ${p}`).join('\n')}\n\n`;
  }

  const techniques = [...new Set(metadata.entities.filter((e) => e.type === 'technique').map((e) => e.name))];
  if (techniques.length > 0) {
    markdown += `## 🔬 Techniques Used\n\n${techniques.map((t) => `- ${t}`).join('\n')}\n\n`;
  }

  markdown += `## 📄 Paper Sections\n\n`;
  for (const section of metadata.sections.slice(0, 5)) {
    const content = section.content.substring(0, 400);
    markdown += `### ${section.name}\n\n${content}...\n\n`;
  }

  markdown += `---\n\n*Ingested: ${new Date().toISOString()}*\n\n`;

  return markdown;
}

// ============================================================================
// MAIN INGESTION PIPELINE WITH HIERARCHY
// ============================================================================

async function main() {
  console.log('\n');
  console.log('╔════════════════════════════════════════════════════════════╗');
  console.log('║  🚀 CORALFILL RECURSIVE PDF INGESTION PIPELINE            ║');
  console.log('║     With Subject-Specific Hierarchies                    ║');
  console.log('╚════════════════════════════════════════════════════════════╝');
  console.log('\n');

  const startTime = Date.now();

  console.log(`📂 Base Directory: ${KNOWLEDGE_BASE_DIR}`);
  console.log(`📝 Wiki Output: ${WIKI_OUTPUT_DIR}`);
  console.log(`🗄️  Database: ${SUPABASE_URL}\n`);

  // Ensure wiki output directory exists
  if (!fs.existsSync(WIKI_OUTPUT_DIR)) {
    fs.mkdirSync(WIKI_OUTPUT_DIR, { recursive: true });
  }

  // Find all PDFs with hierarchy
  console.log('🔍 Scanning for PDFs in all subdirectories...');
  const pdfFiles = findAllPDFsWithHierarchy(KNOWLEDGE_BASE_DIR);

  if (pdfFiles.length === 0) {
    console.error(`\n❌ No PDFs found in ${KNOWLEDGE_BASE_DIR}`);
    console.error('Please ensure PDFs are placed in the knowledge directory or subdirectories.');
    process.exit(1);
  }

  // Group by subject
  const filesBySubject = new Map<string, PDFFile[]>();
  pdfFiles.forEach((file) => {
    if (!filesBySubject.has(file.subject)) {
      filesBySubject.set(file.subject, []);
    }
    filesBySubject.get(file.subject)!.push(file);
  });

  console.log(`✓ Found ${pdfFiles.length} PDF files in ${filesBySubject.size} subject categories\n`);

  // Process by subject
  const directoryStats: DirectoryStats[] = [];
  let totalSuccess = 0;
  let totalSkip = 0;
  let totalError = 0;

  for (const [subject, files] of filesBySubject) {
    const subjectStartTime = Date.now();
    console.log(`\n${'═'.repeat(60)}`);
    console.log(`📚 SUBJECT: ${subject.toUpperCase()}`);
    console.log(`${'═'.repeat(60)}\n`);
    console.log(`📁 Processing ${files.length} PDF(s)...\n`);

    let subjectSuccess = 0;
    let subjectSkip = 0;
    let subjectError = 0;

    for (let i = 0; i < files.length; i++) {
      const file = files[i];
      const filename = path.basename(file.path);
      const progress = `[${i + 1}/${files.length}]`;

      console.log(`${progress} ${filename}`);

      try {
        // Extract text
        const text = await extractTextFromPDF(file.path);
        if (!text || text.trim().length < 100) {
          console.log('  ⚠️  Skipped: No readable text extracted\n');
          subjectSkip++;
          continue;
        }

        // Extract metadata
        const doi = extractDOI(text);
        const metadata: ExtractedPaperData = {
          doi,
          title: null,
          authors: extractAuthorsFromHeader(text),
          publication_year: extractYearFromText(text),
          journal: null,
          abstract: null,
          full_text: text,
          citations: extractCitations(text),
          entities: extractEntities(text),
          sections: extractSections(text),
          relevance_score: scoreRelevanceForCoralResearch(text),
          subject_area: subject, // Set subject
          file_path: file.path,
          relative_path: file.relativePath,
        };

        // Enrich from CrossRef
        if (doi) {
          console.log(`  🔗 Fetching CrossRef metadata...`);
          const crossRefData = await fetchCrossRefMetadata(doi);
          Object.assign(metadata, crossRefData);
          await new Promise((resolve) => setTimeout(resolve, 500));
        }

        // Check duplicates
        if (await checkDuplicatePaper(metadata)) {
          console.log('  ⊘ Skipped: Duplicate paper\n');
          subjectSkip++;
          continue;
        }

        // Insert to database
        const paperId = await insertPaperAndRelatedData(metadata);
        if (!paperId) {
          console.log('  ✗ Failed to insert into database\n');
          subjectError++;
          continue;
        }

        // Generate wiki
        const wikiMarkdown = generateWikiMarkdown(metadata, paperId);
        const wikiFilename = `${paperId}.md`;
        const wikiPath = path.join(WIKI_OUTPUT_DIR, wikiFilename);
        fs.writeFileSync(wikiPath, wikiMarkdown, 'utf-8');

        console.log(`  ✓ Successfully ingested`);
        console.log(`    Title: ${metadata.title?.substring(0, 50) || 'Unknown'}`);
        console.log(`    Subject: ${subject}`);
        console.log(`    Path: ${file.relativePath}`);
        console.log(`    Entities: ${metadata.entities.length} (Species: ${metadata.entities.filter((e) => e.type === 'species').length}, Compounds: ${metadata.entities.filter((e) => e.type === 'compound').length})`);
        console.log(`    Relevance: ${(metadata.relevance_score * 100).toFixed(1)}%\n`);

        subjectSuccess++;
      } catch (error) {
        console.log(`  ✗ Error: ${error instanceof Error ? error.message : 'Unknown error'}\n`);
        subjectError++;
      }

      await new Promise((resolve) => setTimeout(resolve, 300));
    }

    const subjectTime = (Date.now() - subjectStartTime) / 1000;
    directoryStats.push({
      directory: subject,
      subject: subject,
      pdfCount: files.length,
      successCount: subjectSuccess,
      skipCount: subjectSkip,
      errorCount: subjectError,
      totalTime: subjectTime,
    });

    console.log(`${'─'.repeat(60)}`);
    console.log(`📊 Subject Summary: ${subject}`);
    console.log(`  ✓ Ingested: ${subjectSuccess}`);
    console.log(`  ⊘ Skipped: ${subjectSkip}`);
    console.log(`  ✗ Errors: ${subjectError}`);
    console.log(`  ⏱️  Time: ${subjectTime.toFixed(1)}s\n`);

    totalSuccess += subjectSuccess;
    totalSkip += subjectSkip;
    totalError += subjectError;
  }

  // Final summary
  const totalTime = (Date.now() - startTime) / 1000;

  console.log('\n' + '═'.repeat(60));
  console.log('📊 COMPLETE INGESTION SUMMARY');
  console.log('═'.repeat(60));
  console.log('\n📚 By Subject Category:\n');

  directoryStats.forEach((stat) => {
    console.log(`${stat.subject.toUpperCase()}`);
    console.log(`  ✓ Success: ${stat.successCount}`);
    console.log(`  ⊘ Skipped: ${stat.skipCount}`);
    console.log(`  ✗ Errors: ${stat.errorCount}`);
    console.log(`  ⏱️  Time: ${stat.totalTime.toFixed(1)}s\n`);
  });

  console.log('─'.repeat(60));
  console.log('\n📊 OVERALL TOTALS\n');
  console.log(`  ✓ Successfully ingested: ${totalSuccess}`);
  console.log(`  ⊘ Skipped (duplicates): ${totalSkip}`);
  console.log(`  ✗ Errors: ${totalError}`);
  console.log(`  📁 Total files scanned: ${pdfFiles.length}`);
  console.log(`  📚 Subject categories: ${filesBySubject.size}`);
  console.log(`  📝 Wiki files created: ${totalSuccess}`);
  console.log(`  ⏱️  Total time: ${totalTime.toFixed(1)}s`);
  console.log(`  📊 Avg per file: ${(totalTime / (pdfFiles.length || 1)).toFixed(1)}s`);
  console.log(`\n${'═'.repeat(60)}\n`);

  if (totalError === 0 && totalSuccess > 0) {
    console.log('✅ ALL SYSTEMS OPERATIONAL\n');
  } else if (totalSuccess > 0) {
    console.log('⚠️  SOME ISSUES - Review above\n');
  } else {
    console.log('❌ NO FILES PROCESSED\n');
  }
}

main().catch((error) => {
  console.error('Fatal error:', error);
  process.exit(1);
});

